/*!40000 ALTER TABLE `tcf_ee_task_documents` DISABLE KEYS */;
INSERT IGNORE INTO `tcf_ee_task_documents` (`id`, `task_id`, `doc_number`, `title`, `content`, `sort_order`) VALUES (346,527,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(347,527,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(348,530,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(349,530,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(350,533,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Christine, 56 ans :<br>\r\n                        Tous les ans, en hiver, je donne un peu de mon temps et de mon argent pour aider les personnes qui vivent dans la rue et ont froid. Pour moi, c\'est important de se soucier de ceux qui sont dans le besoin. Je trouve très important de donner quelques dollars à ces personnes ou aux associations qui peuvent les aider. Et puis, cette action me donne l\'impression d\'être utile, au moins une fois dans l\'année ! C\'est un geste de solidarité qui est à la portée de tout le monde.</p>',1),(351,533,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Pierre, 65 ans :<br>\r\n                        Plutôt que de donner de l\'argent à des personnes pauvres, il vaudrait mieux revoir notre mode de vie. C\'est pourquoi je préfère m\'engager au quotidien dans une association de mon quartier, où je suis bénévole. Les sans domicile fixe ont besoin d\'un logement et d\'un travail et pas seulement d\'argent. Il faut les aider à devenir autonomes. C\'est le but d\'organismes qui aident ceux qui sont dans la rue à trouver un emploi. Donner de l\'argent est un acte inutile qui sert seulement à apaiser notre conscience.</p>',2),(352,536,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec l\'avancée technologique et les produits high-tech qui envahissent de plus en plus notre quotidien, nos enfants oublient la lecture et s\'intéressent davantage aux jeux vidéo, aux sports, à la musique… Contrairement à nous les adultes, dont beaucoup d\'entre-nous ont lu des milliers de pages, la génération actuelle est toujours occupée par les réseaux sociaux et le gaming ou prennent du plaisir à pratiquer du sport qui attirent davantage de jeunes grâce aux stars internationales du football, du tennis, de l\'athlétisme… alors avec tout ça, pourquoi devons-nous forcer les enfants à lire un bouquin ? Et comme le dit un proverbe, \"le goût de la lecture ne peut pas s\'imposer\"… il faut laisser l\'enfant choisir ce qu\'il veut lire et surtout ne pas l\'obliger à lire quand il n\'a pas envie.</p>',1),(353,536,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>L\'amour de la lecture se transmet de génération en génération bien que, ces dernières années, on ne trouve plus beaucoup de bouquins entre les mains des enfants, laissant la place aux smartphones et aux tablettes. En apprenant à lire régulièrement, l\'enfant acquiert le langage plus aisément tout en développant sa capacité d\'audition et de concentration. De plus, et pour prendre du plaisir ensemble, les parents peuvent consacrer quotidiennement 10 minutes à leurs enfants pour lire des bouquins ; une activité qui renforcera à coup sûr la complicité parent/enfant.</p>',2),(354,539,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(355,539,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(356,542,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>À la rentrée, le nombre d\'élèves inscrits dans des écoles privées a augmenté en France. Le succès des établissements privés n\'est pas directement lié aux bons résultats scolaires de leurs élèves. C\'est la réputation de ces lieux qui explique un tel enthousiasme. Aux yeux de nombreux parents, les élèves y sont mieux encadrés, mieux surveillés et les professeurs sont plus présents. Les parents sont aussi rassurés parce que les classes sont homogènes : elles accueillent généralement des élèves de milieux sociaux favorisés. En effet, les études dans ces établissements sont payantes, ce qui n\'est pas le cas dans les écoles publiques.</p>',1),(357,542,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Dans les collèges privés, il y a peu d\'élèves de milieux sociaux défavorisés. Comme les études dans ces établissements sont payantes, certaines catégories de population en sont exclues. Ce système qui oppose écoles publiques et écoles privées ne facilite pas la mixité sociale. Ainsi, les élèves du privé ont rarement l\'occasion de rencontrer d\'autres jeunes issus de milieux sociaux moins favorisés qu\'eux et inversement. Ce modèle scolaire reproduit les inégalités sociales et renforce le sentiment d\'exclusion de certains jeunes.</p>',2),(358,545,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivire les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(359,545,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(360,548,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Jean : Je suis fermement convaincu que l\'intégration des nouvelles technologies dans les écoles est cruciale pour préparer les élèves à un avenir numérique. Je pense que l\'usage des tablettes et des ordinateurs stimule non seulement l\'engagement des élèves mais enrichit également leur expérience éducative en leur offrant un accès facile à une variété de ressources, encourageant ainsi leur créativité et autonomie.</p>',1),(361,548,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Sara : Je suis sceptique quant à l\'usage intensif des technologies dans l\'enseignement. Je crois que cela peut réduire les interactions humaines essentielles et favoriser une dépendance préoccupante aux écrans. À mon avis, les méthodes d\'enseignement traditionnelles et le contact direct entre enseignants et élèves restent indispensables pour un développement équilibré et complet des compétences des jeunes.</p>',2),(362,551,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(363,551,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(364,554,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le supermarché est très pratique ; on y trouve une grande variété de produits, tous à portée de main. Vous pouvez garer votre voiture dans le parking et faire le tour des rayons pour acheter tout ce dont vous avez besoin : fruits, légumes, fromages, viandes, boissons… De plus, les supermarchés offrent plusieurs marques pour un même produit, tout en proposant régulièrement des promotions et des remises.</p>',1),(365,554,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>ASSOCIATION POUR LA SAUVEGARDE DES PETITS COMMERCES</p>\r\n                    <p>Le défi « Février sans supermarché » a été créé pour limiter la superpuissance des supermarchés et, par conséquent, permettre aux petits commerces de survivre et de réaliser des chiffres d\'affaires plus conséquents. Ce défi consiste à boycotter les supermarchés pendant une durée d\'un mois, en faisant toutes ses courses dans les épiceries de quartier. Le client aura tout à gagner : il bénéficiera non seulement de produits frais de meilleure qualité, mais aura également l\'opportunité de papoter avec les voisins.</p>',2),(366,557,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Je vais bientôt avoir 22 ans et j\'habite toujours chez mes parents. Mon père et ma mère restent autoritaires avec moi, même si je suis majeure. Quand j\'étais mineure, je n\'avais pas le droit de dormir dehors, ni même de dépasser 21h lorsque je sortais avec des amies. Maintenant, peu de choses ont changé ; certes, j\'ai le droit de veiller plus tard la nuit, mais ma mère ne cesse de m\'appeler sur mon téléphone portable jusqu\'à ce que je sois de retour.</p>',1),(367,557,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les parents ont parfois peur d\'être trop sévères avec leurs enfants. Ils craignent, qu\'à cause d\'un excès d\'autorité, leurs enfants ne s\'épanouissent pas et manquent plus tard de personnalité. Même si les parents acceptent, par amour, tout ce dont leurs enfants demandent, cela pourrait avoir des effets négatifs lorsqu\'ils passent à l\'âge adulte. En effet, pour vivre en communauté, il y a certaines règles à respecter.</p>',2),(368,560,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Je suis en faveur des distributeurs de boissons dans les lycées. Premièrement, ils offrent une commodité supplémentaire pour les élèves, notamment pour ceux qui n\'ont pas le temps de passer à la cafétéria pendant les pauses. Deuxièmement, s\'ils sont bien gérés, ces distributeurs peuvent offrir une gamme de boissons saines, comme de l\'eau, du jus de fruits pur et des boissons aux fruits sans sucre ajouté. Ces distributeurs peuvent être une source de revenus supplémentaire pour l\'école, qui peut être réinvestie dans l\'amélioration des infrastructures ou des programmes scolaires.</p>',1),(369,560,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Je suis contre l\'installation de distributeurs de boissons dans les lycées. Ma principale préoccupation est liée à la santé des élèves. Malheureusement, beaucoup de ces distributeurs sont remplis de boissons sucrées et de sodas qui contribuent à l\'obésité infantile et à d\'autres problèmes de santé comme le diabète. Même les jus de fruits, qui peuvent sembler sains, contiennent souvent beaucoup de sucre. Les écoles devraient être des lieux qui encouragent des habitudes alimentaires saines et je crains que la présence de ces distributeurs n\'encourage une consommation excessive de boissons sucrées.</p>',2),(370,563,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(371,563,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(372,566,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(373,566,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(374,569,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Christine, 56 ans :<br>\r\n                    Tous les ans, en hiver, je donne un peu de mon temps et de mon argent pour aider les personnes qui vivent dans la rue et ont froid. Pour moi, c\'est important de se soucier de ceux qui sont dans le besoin. Je trouve très important de donner quelques dollars à ces personnes ou aux associations qui peuvent les aider. Et puis, cette action me donne l\'impression d\'être utile, au moins une fois dans l\'année ! C\'est un geste de solidarité qui est à la portée de tout le monde.</p>',1),(375,569,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Pierre, 65 ans :<br>\r\n                    Plutôt que de donner de l\'argent à des personnes pauvres, il vaudrait mieux revoir notre mode de vie. C\'est pourquoi je préfère m\'engager au quotidien dans une association de mon quartier, où je suis bénévole. Les sans domicile fixe ont besoin d\'un logement et d\'un travail et pas seulement d\'argent. Il faut les aider à devenir autonomes. C\'est le but d\'oganismes qui aident ceux qui sont dans la rue à trouver un emploi. Donner de l\'argent est un acte inutile qui sert seulement à apaiser notre conscience.</p>',2),(376,572,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>le texte affirme que les zoos ont beaucoup d\'avantages, même pour les animaux en la voie de disparition, les animaux sont bien soignées dans les zoos. Les études montrent que le nombre de reproduction a augmenté grâce aux zoos et ils peuvent sauver la vie des animaux.</p>',1),(377,572,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>le texte a montré qu\'il ne faut pas mettre les animaux sauvages dans les zoos parce que ce n\'est pas leur environnement. C\'est un prison pour eux. On trouve des ours polaires dans un zoo dont la température est de 15 degrés. Les animaux ont besoin de la nature et de la liberté.</p>',2),(378,575,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Beaucoup de gens pensent encore que les jeux vidéo nous rendent bêtes. Pourtant de nombreuses études prouvent le contraire. Ainsi, selon une de ces études, les utilisateurs de jeux de course développeraient leur sens de l\'orientation, leur mémoire et la précision de leurs mouvements. D\'autres études montrent clairement une amélioration de la rapidité et de la concentration de tous les joueurs. Et c\'est sans parler des jeux d\'entraînement destinés aux personnes âgées pour consolider la mémoire et la vivacité d\'esprit… Bref, c\'est scientifique, le jeu vidéo rend plus intelligent !</p>',1),(379,575,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Les jeux vidéo, sur console ou sur ordinateur, chez soi ou en salle, seul, avec des amis ou en ligne avec des inconnus, peuvent provoquer une dépendance chez certaines personnes. On parle d\'addiction quand le jeu vidéo devient le principal (ou l\'unique) centre d\'intérêt, à la place d\'autres activités (relationnelle, professionnelle, scolaire, loisirs, sport…). Cette dépendance est particulièrement préoccupante lors de l\'adolescence, période importante où les jeux vidéo peuvent avoir un impact négatif sur les résultats scolaires.</p>',2),(380,578,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(381,578,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(382,581,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(383,581,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(384,584,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>De plus en plus d\'écoles décident de mettre en place un menu sans viande dans les cantines, au moins deux fois par semaine. Certaines études ont montré que les enfants consomment trop de protéines animales. C\'est donc une question de santé : les écoles ont choisi de remplacer la viande par d\'autres produits (soja, céréales, légumes), moins gras et utiles à la croissance des enfants. Ces menus sans viandes à la cantine reviennent moins cher aux familles. Cette idée plaît beaucoup aux parents comme aux enfants.</p>',1),(385,584,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La décision de supprimer la viande dans les cantines ne plaît pas à tout le monde. En effet, c\'est un produit cher : la cantine est le seul endroit où les enfants de familles en difficulté peuvent manger. Les producteurs locaux de viande sont également mécontents : une partie de leur production est réservée aux cantines, il s\'agit donc d\'une perte financière. Enfin, beaucoup d\'enfants interrogés déclarent tout de même préférer les steaks de bœuf aux steaks de soja qui, selon eux, ont peu de goût.</p>',2),(386,587,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(387,587,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, …)</p>',2),(388,590,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d\'hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(389,590,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l\'environnement.</p>',2),(390,593,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le port de l\'uniforme étouffe et écrase la personnalité des garçons. Ils ne peuvent s\'habiller comme ils veulent, en aucune circonstance. De l\'autre coté de l\'échelle (chez les pros) il y a des gens qui préféraient pour eux-mêmes et leurs enfants, avoir la possibilité de s\'exprimer à travers l\'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers la mode, se démarquer de la foule grâce à un accessoire ou un vêtement particulier, se retrouveront déçus et emprisonnés dans l\'uniforme.</p>',1),(391,593,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le port de l\'uniforme développe un sentiment d\'appartenance à son établissement, et à la communautés des élèves. Il nourrit chez le jeune le sens du collectif et engendre souvent la fierté d\'appartenir à son établissement. De plus, il réduit la discrimination basée sur le style ou sur la classe sociale de l\'élève. En effet, l\'uniforme permet aux parents d\'économiser beaucoup d\'argents, ce ne sont pas tous les parents qui peuvent payer à leurs enfants de beaux vêtements griffés ou de marques populaires. La mise en place d\'un code vestimentaire réduit donc les différences entre les classes sociales.</p>',2),(392,596,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Des études ont montré que certaines zones du cerveau de l\'adulte peuvent être développées en jouant aux jeux vidéo. Ainsi, il peut être intéressant de jouer aux jeux vidéo, car ils permettent, par exemple, d\'améliorer la capacité d\'analyse, la capacité à faire des choix et la rapidité de réaction. C\'est une bonne nouvelle car la répartition des joueurs par âge montre que 83% des joueurs sont des adultes. Cependant, il convient de rester prudent car certains jeux vidéos ne favorisent pas ce type d\'amélioration sur le cerveau.</p>',1),(393,596,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Pendant trois ans, des enfants âgés de 8 à 17 ans ont participé à une étude sur les jeux vidéo. Les résultats de cette étude montrent que les enfants qui jouent beaucoup aux jeux vidéo sont plus violents, plus nerveux et plus stressés que ceux qui ne jouent pas ou peu. Ceux qui jouent beaucoup ont également moins de bons résultats à l\'école. Il est donc conseillé aux parents d\'être vigilants et de limiter l\'usage de ces jeux par leurs enfants.</p>',2),(394,599,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Certains postes sont majoritairement occupés par des hommes. Au Québec, l\'égalité entre les femmes et les hommes est respectée, les femmes peuvent les métiers réservés aux hommes tel que les postes de direction.</p>',1),(395,599,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Malgré les efforts pour imposer la parité à tous les postes dans les entreprises et les collectivités, il y a, dans les faits, des métiers où les femmes sont largement majoritaires tels que : les sage-femmes. De plus, les femmes ne doivent pas faire les métiers d\'homme, car ils doivent prendre soin de ses enfants.</p>',2),(396,602,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(397,602,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(398,605,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Opinion 1 : Alexandre, un conseiller d\'orientation</p>\r\n                    <p>\"Je suis fermement pour le travail des jeunes pendant les vacances. C\'est une excellente occasion d\'acquérir des compétences pratiques, d\'apprendre à travailler en équipe et de découvrir différentes industries. Les jeunes peuvent gagner de l\'argent qu\'ils peuvent économiser pour l\'avenir ou utiliser pour financer des activités ou des loisirs. De plus, le fait d\'avoir une expérience de travail sur leur CV peut leur donner un avantage lorsqu\'ils postulent pour des emplois ou des stages à l\'avenir. Les vacances d\'été sont longues et il y a amplement de temps pour se reposer et travailler.\"</p>',1),(399,605,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Opinion 2 : Élise, une psychologue pour adolescents</p>\r\n                    <p>\"Je suis contre l\'idée que les jeunes doivent travailler pendant leurs vacances. Les adolescents sont déjà sous une énorme pression pendant l\'année scolaire avec les études, les examens et les activités parascolaires. Les vacances doivent être une période pour eux de se détendre, de se décompresser et de poursuivre des intérêts personnels. Les forcer à travailler pourrait contribuer au stress et à l\'épuisement. Il est également important pour les jeunes de disposer de temps non structuré pour explorer leur créativité, passer du temps avec leurs amis et leur famille, et tout simplement être des enfants. Le travail peut attendre.\"</p>',2),(400,608,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Jean qui vit à la compagne favorise l\'achat des produits alimentaires directement à la ferme pour la bonne qualité quitte à payer un peu plus cher.</p>',1),(401,608,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Camille qui vit dans la ville préfère faire ses courses au supermarché pour la variété qu\'il propose et pour les prix abordables.</p>',2),(402,611,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les raisons qui poussent les parents à opter pour la scolarisation à domicile sont nombreuses. Elle donne la possibilité d\'adopter une pédagogie plus individualisée. On peut passer plus de temps sur les points sur lesquels l\'enfant bute ou lui proposer, à l\'occasion, des jeux éducatifs. L\'enfant gère son apprentissage à son rythme, il creuse les sujets qui le passionnent et ne subit pas la pression des autres élèves qui peuvent avancer plus au moins vite que lui. Autre avantage de l\'instruction en famille, une évolution différente. Avec l\'école à la maison, pas de notes qui peuvent parfois être décourageantes, mais un contrôle continu des connaissances, pas de stress dû aux évaluations et aux devoirs.</p>',1),(403,611,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le choix de la scolarisation à domicile représente un véritable défi et donc, quelques inconvénients à prendre en compte avant de se lancer. La scolarisation à domicile nécessite beaucoup de temps, une bonne organisation et elle a aussi un coût. Tout le matériel, les livres, les manuels, et les sorties sont à la charge des familles, et l\'un des deux parents est souvent amené à mettre entre parenthèses son emploi. Au total, l\'école à domicile coûte généralement plus cher qu\'une scolarisation dans le public. De plus, l\'enfant ne côtoie pas de camarades au quotidien, car l\'école à domicile ne permet pas à l\'enfant d\'entrer en interaction avec d\'autres enfants comme il le ferait dans un cadre scolaire classique.</p>',2),(404,614,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Quand on parle de vélo, on pense systématiquement à deux choses: sport et loisir. On oublie souvent que c\'est avant tout un mode de déplacement personnel et professionnel. En ville, c\'est un moyen de transport rapide et déstressant puisqu\'il permet d\'éviter les interminables embouteillages aux heures de pointe. Se rendre au travail tout en faisant du sport, histoire de joindre l\'utile à l\'agréable.</p>',1),(405,614,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Avec tous les accidents de la route observés annuellement, sortir son vélo pour se déplacer avec en ville peut être très dangereux. En effet, avec la densité importante de véhicules, le non-respect du Code de la route et le manque de pistes cyclables, pratiquer du vélo en zone urbaine présente de vrais risques d\'accident. De plus, faire du vélo de nos jours, c\'est s\'exposer à des gaz d\'échappement toxiques et nocifs pour la santé humaine (notamment le monoxyde de carbone…).</p>',2),(406,617,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(407,617,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(408,620,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Dans nos jours, les villes grossissent toujours plus. Malheureusement, ce phénomène a un impact fort sur l’environnement. Car plus une ville grossis, plus elle a des effets négatifs sur la nature et donc, ensuite, sur l’homme. L’effet négatif le plus visible est la déforestation, qui augmente le végétaux qui retiennent le carbone. Donc, quand on les supprime pour construire des bâtiments ou des rues,on supprime de espaces verts capables de retenir des millions de tonnes de carbone.</p>',1),(409,620,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Plus de la moitié de l’humanité vit en ville (huit habitants sur dix dans les pays riches) la vie urbaine est donc le principal enjeu écologique.On entend souvent dire que l’organisation actuelle des villes n’est pas écologique, et que le grossissement des villes ne fait qu’augmenter le problème. Pourtant, il faut se méfier des apparences : les villes ne sont pas toujours aussi antiécologique qu’on l’imagine. Par exemple, la consommation d’énergie d’un citadin est moins importante que celle d’un habitant de la campagne.</p>',2),(410,623,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivre les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(411,623,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(412,626,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les objets connectés facilitent notre vie quotidienne. Ce sont des objets ou des équipements pilotés à distance à l\'aide d\'un téléphone portable ou par Internet, comme le système de chauffage ou la fermeture des portes. De plus, avec une montre ou un bracelet connecté, toutes nos activités peuvent être analysées. Un logiciel va mesurer le nombre de nos pas pour nous inciter à faire davantage d\'exercice. Un domaine où l\'on comprend mieux leur utilité est celui de la surveillance de la santé. Certains objets agissent comme un carnet de santé, toujours prêts à vous rappeler un rendez-vous chez le médecin ou des médicaments à prendre.</p>',1),(413,626,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il y aurait 50 milliards d\'objets connectés dans le monde : l\'alarme, le téléviseur, la caméra de surveillance, les volets, le détecteur de fumée, etc. Face à cette évolution, la question de la sécurité se pose. En effet, un pirate informatique peut prendre le contrôle d\'un objet connecté en quelques minutes. Ou encore, un cambrioleur pourrait vérifier grâce aux caméras de surveillance connectées d\'une habitation si les occupants sont absents. Il est aussi possible d\'entrer dans le système connecté d\'une voiture et d\'en prendre les commandes à distance.</p>',2),(414,629,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Les avantages penser à l\'avenir, avoir les vêtements propres être en confort surtout que les argents n\'est pas tjrs suffisante, Vivre avec ces parents pendant la période des études permet aux jeunes d\'économiser les frais de logement, des plats faits maison et une certaine stabilité psychique, teste les adolescents qui vivent avec leurs parents lui permettent d\'économiser son argent pour des projets de vie(il paye pas ni le loyer ni la nourriture) (pour ne pas payer le loyer qui coûte chers, le ménage est fait, les vêtements est propres).. favorise que les jeunes vivent avec leurs parents avec le témoin de deux jeunes, la jeune fille disait que le Loyer est très chère et étudier loin de chez soi revient plus chère, Le deuxième jeune trouve que vivre avec ses parents est plus bénéfique pour lui par exemple: la bouffe est bonne, vêtements toujours propres et y a pas de place pour la solitude.</p>',1),(415,629,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Les inconvénients manque de liberté, Vivre seuls leur permet d\'être indépendant, les adolescents qui vivent Avec leurs parents s\'ennuient car leurs parents décident à leur place et se sont toujours de pondant des parents [...] un avis d\'un certain monsieur qui à 25 et il a perdu son job, donc il était dans l\'obligation de rentrer vivre avec ces parents, et maintenant il a perdu son espace d\'intimitée ... contre la vie des jeunes avec leurs parent, un témoignage d\'un jeune qui considère revenir chez ces parents c\'est avoir revenir en arrières.</p>',2),(416,632,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Les enfants de l\'école primaire peuvent utiliser la technologie pour trouver des vidéos sur les sujets qu\'ils ont étudiés à l\'école ou pour jouer à des jeux qui améliorent leur aisance en mathématiques, leur compréhension de la lecture ou leurs compétences en dactylographie.</p>',1),(417,632,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Les nouvelles technologies encouragent les enfants à être sédentaires. C\'est une préoccupation majeure pour les parents. Cela ne mène à aucun jeu libre créatif, à aucune interaction sociale face à face, conduisant à aucun effort physique! Pourquoi ne pas essayer certaines de ces activités amusantes pour encourager vos enfants à ranger leurs appareils ?</p>',2),(418,635,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec l\'avancée technologique et les produits high-tech qui envahissent de plus en plus notre quotidien, nos enfants oublient la lecture et s\'intéressent davantage aux jeux vidéo, aux sports, à la musique… Contrairement à nous les adultes, dont beaucoup d\'entre-nous ont lu des milliers de pages, la génération actuelle est toujours occupée par les réseaux sociaux et le gaming ou prennent du plaisir à pratiquer du sport qui attirent davantage de jeunes grâce aux stars internationales du football, du tennis, de l\'athlétisme… alors avec tout ça, pourquoi devons-nous forcer les enfants à lire un bouquin ? Et comme le dit un proverbe, \"le goût de la lecture ne peut pas s\'imposer\"… il faut laisser l\'enfant choisir ce qu\'il veut lire et surtout ne pas l\'obliger à lire quand il n\'a pas envie.</p>',1),(419,635,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>L\'amour de la lecture se transmet de génération en génération bien que, ces dernières années, on ne trouve plus beaucoup de bouquins entre les mains des enfants, laissant la place aux smartphones et aux tablettes. En apprenant à lire régulièrement, l\'enfant acquiert le langage plus aisément tout en développant sa capacité d\'audition et de concentration. De plus, et pour prendre du plaisir ensemble, les parents peuvent consacrer quotidiennement 10 minutes à leurs enfants pour lire des bouquins ; une activité qui renforcera à coup sûr la complicité parent/enfant.</p>',2),(420,638,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Dans nos jours, les villes grossissent toujours plus. Malheureusement, ce phénomène a un impact fort sur l\'environnement. Car plus une ville grossis, plus elle a des effets négatifs sur la nature et donc, ensuite, sur l\'homme. L\'effet négatif le plus visible est la déforestation, qui augmente le végétaux qui retiennent le carbone. Donc, quand on les supprime pour construire des bâtiments ou des rues,on supprime de espaces verts capables de retenir des millions de tonnes de carbone.</p>',1),(421,638,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Plus de la moitié de l\'humanité vit en ville (huit habitants sur dix dans les pays riches) la vie urbaine est donc le principal enjeu écologique.On entend souvent dire que l\'organisation actuelle des villes n\'est pas écologique, et que le grossissement des villes ne fait qu\'augmenter le problème. Pourtant, il faut se méfier des apparences : les villes ne sont pas toujours aussi antiécologique qu\'on l\'imagine. Par exemple, la consommation d\'énergie d\'un citadin est moins importante que celle d\'un habitant de la campagne.</p>',2),(422,641,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>De plus en plus de gens louent leur logement ou une chambre à des voyageurs, pour gagner un revenu supplémentaire ou pour rencontrer de nouvelles personnes. Ce système, basé sur la confiance, permet aux visiteurs de se loger en payant moins cher que dans un hôtel. De plus, si le propriétaire est d\'accord, ils peuvent même utiliser la cuisine et éviter d\'aller au restaurant! La personne qui les accueille peut leur servir de guide et les conseiller sur les visites à faire. C\'est un échange précieux pour tout le monde!</p>\r\n                    <p>D\'après rapidloc.com</p>',1),(423,641,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>L\'année dernière, j\'ai loué mon appartement à un couple de touristes pour leurs vacances d\'une semaine à Marseille. C\'était une très mauvaise expérience qui m\'a fait changer d\'avis sur ce mode de location! Ils sont arrivés en retard et j\'ai dû les attendre pour leur donner la clé. Ils ont fait beaucoup de bruit et dérangé mes voisins. En plus, ils ont quitté mon appartement sans faire la vaisselle et en laissant leurs déchets. J\'ai passé trois heures à nettoyer.</p>\r\n                    <p>Julien, 38 ans</p>',2),(424,644,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les vêtements de marques sont très important pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(425,644,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(426,647,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(427,647,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, …)</p>',2),(428,650,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Vivre avec d\'autres personnes demande d\'avoir une bonne entente et de respecter certaines règles. Il n\'est pas toujours possible d\'écouter sa musique préférée à volume élevé, d\'inviter tous ses amis pour faire la fête ou de laisser de la vaisselle sale dans la cuisine. Chaque individu a des habitudes susceptibles d\'irriter les autres. C\'est pourquoi il est essentiel d\'établir des règles de vie en communauté et de les respecter mutuellement. Il est important de communiquer avec ses colocataires chaque fois qu\'un problème survient. L\'organisation et la discussion sont les clés d\'une colocation réussie ou non.</p>',1),(429,650,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Être adulte et vivre en colocation ? C\'est un choix qui permet d\'accéder facilement à un logement plus spacieux et économique. Il est vrai que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager la cuisine, le salon et la salle de bain. Toutefois, une colocation peut inclure une maison avec jardin ou un grand appartement en centre-ville ! De plus, en partageant le loyer et les charges avec vos colocataires, vous réduirez considérablement vos dépenses par rapport à un appartement individuel. Alors que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager les espaces communs, une colocation offre des opportunités de logements bien plus abordables.</p>',2),(430,653,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d\'offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d\'information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(431,653,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d\'autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d\'un sport. Il est important de faire preuve de discernement et de réguler l\'exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d\'apprentissage et de divertissement.</p>',2),(432,656,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(433,656,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(434,659,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Apprendre une langue en ligne grace à Internet, c\'est possible et cela donne de bons résultats ! Contrairement aux cours classiques, on peut apprendre quand on veut : les cours sont disponibles tout le temps. Cela permet de mieux organiser sa journée. On n\'a pas non plus besoin de faire des kilomètres pour aller dans une école de langues. On peut apprendre de son salon, de son bureau ou même d\'un café près de chez soi ! Cela permet aussi de faire des économies.</p>',1),(435,659,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cela semble facile d\'apprendre une langue en ligne mais ce n\'est pas possible pour tout le monde. En effet, il faut avoir une bonne connexion à Internet et un outil numérique adapté (ordinateur, smartphone, tablette) pour apprendre en ligne. De plus, il faut être très autonome pour être capable d\'apprendre seul : il est difficile de se mettre au travail chez soi et de rester motivé quand on n\'a pas l\'aide d\'un professeur et de collègues. Dans ces conditions, on peut se décourager et abandonner très vite.</p>',2),(436,662,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l\'avantage est avant tout économique. D\'une part, le livre numérique permet d\'économiser du papier, d\'autre part la version numérique d\'un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d\'augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(437,662,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le livre numérique remplacera-t-il le livre papier ? « Non », répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu\'on aime ou de l\'offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l\'odeur du neuf ou de l\'ancien… Il transmet beaucoup d\'émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(438,665,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La gratuité des musées peut entraîner une surfréquentation, ce qui nuit à la qualité de l\'expérience des visiteurs. De plus, cela peut réduire les ressources financières des musées, affectant ainsi leur entretien et la préservation des œuvres. Un tarif réduit serait une meilleure solution pour rendre la culture accessible tout en soutenant les musées.</p>',1),(439,665,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La gratuité des musées est une excellente initiative. Cela rend la culture accessible à tous, indépendamment de leur situation financière. J\'ai pu visiter plusieurs musées gratuitement, ce qui m\'a permis d\'enrichir mes connaissances sans me soucier du coût. Pour moi, la gratuité des musées contribue à l\'éducation du public et au partage du patrimoine culturel.</p>',2),(440,668,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Avantages des cours en ligne (flexibilité, accessibilité, économies).</p>',1),(441,668,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Limites de l\'apprentissage en ligne (nécessité de discipline, accès à Internet, manque d\'interaction humaine).</p>',2),(442,671,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d\'hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(443,671,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l\'environnement.</p>',2),(444,674,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                <p>Je vais bientôt avoir 22 ans et j\'habite chez mes parents. Malgré ma majorité, mes parents restent autoritaires avec moi. Lorsque j\'étais mineure et que je sortais avec des amies, je n\'avais pas le droit de dormir dehors ni même de dépasser 21h. Aujourd\'hui, peu de choses ont changé. Certes, j\'ai le droit de veiller plus tard, mais ma mère ne cesse de m\'appeler sur mon téléphone portable jusqu\'à ce que je sois de retour chez nous.</p>',1),(445,674,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                <p>Les parents ont parfois peur d\'être trop sévères avec leurs enfants. Ils craignent qu\'à cause d\'un excès d\'autorité, leurs enfants ne s\'épanouissent pas et manquent de personnalité plus tard. Même si, par amour, les parents acceptent tout ce que leurs enfants demandent, cela pourrait avoir des effets négatifs lorsqu\'ils passent à l\'âge adulte. En effet, pour vivre en communauté, il est nécessaire de respecter certaines règles.</p>',2),(446,677,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les amitiés entre collègues au travail peuvent être extrêmement bénéfiques. Elles favorisent un climat de travail agréable et une ambiance positive au sein de l\'équipe. Avoir des amis parmi ses collègues permet de renforcer les liens professionnels et de créer un sentiment de camaraderie. Cela peut contribuer à une meilleure communication, une collaboration plus étroite et une résolution plus efficace des problèmes. De plus, partager des moments de convivialité en dehors du travail, comme des déjeuners ou des activités après le bureau peut renforcer les liens et créer une dynamique de groupe solide.</p>',1),(447,677,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Il est important de trouver un équilibre entre amitié et professionnalisme au travail. Les amitiés excessivement proches peuvent parfois créer des tensions ou des conflits lorsque des décisions professionnelles doivent être prises. De plus, les amitiés exclusives entre certains collègues peuvent exclure les autres membres de l\'équipe, ce qui peut nuire à la cohésion et à la collaboration. Il est essentiel de maintenir des limites claires et de veiller à ce que les amitiés ne compromettent pas le professionnalisme, la hiérarchie ou la productivité au sein de l\'organisation.</p>',2),(448,680,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Témoignage d\'Aïcha, qui préfère manger à l\'extérieur pour partager des moments conviviaux et éviter de cuisiner.</p>',1),(449,680,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Témoignage de Laura, qui préfère cuisiner chez elle pour des raisons financières et de qualité alimentaire.</p>',2),(450,683,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Avantages du livre numérique (économie de papier, accessibilité pour les personnes en situation de handicap, coût réduit).</p>',1),(451,683,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Défense du livre papier (plaisir de la lecture traditionnelle, valeur sentimentale, accessibilité pour tous).</p>',2),(452,686,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Impact environnemental négatif du plastique (pollution des océans, impact sur la faune et la santé humaine).</p>',1),(453,686,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Importance du plastique dans le domaine médical (dispositifs essentiels pour la santé, prévention des infections).</p>',2),(454,689,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(455,689,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(456,692,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(457,692,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(458,695,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(459,695,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(460,698,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Grâce à la livraison en entreprise, les employés bénéficieront d’un gain de temps notable. Il n’est plus question d’aller sortir loin du lieu de travail pour trouver de quoi manger. En complément, l’argent et l’énergie économisée permettent d’être encore plus efficace au travail. Sans pour autant mettre fin à une session importante liée au travail, le repas sera déjà prêt et pourra attendre la fin d’une conférence, d’une réunion ou d’un rendez-vous. Il s’agit d’une véritable solution dédiée aux entreprises ayant une activité intense et qui requiert la présence continue de leurs employés.</p>',1),(461,698,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l’attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(462,701,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d’offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d’information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(463,701,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d’autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d’un sport. Il est important de faire preuve de discernement et de réguler l’exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d’apprentissage et de divertissement.</p>',2),(464,704,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Franck soutient l\'utilisation limitée du plastique, soulignant son importance dans de nombreux secteurs, notamment les secteurs médical et alimentaire. Pour lui, le plastique est vital pour la conservation des aliments et la stérilisation des équipements médicaux. Il prône une utilisation responsable et le recyclage, mais reconnaît que certains usages du plastique sont indispensables pour la société moderne.</p>',1),(465,704,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Amicha s\'oppose fermement à l\'utilisation du plastique, mettant en avant son impact environnemental dévastateur. Elle soutient que les déchets plastiques polluent les océans et les écosystèmes, causant des dommages irréparables. Amicha milite pour des alternatives écologiques et durables, insistant sur l\'urgence de renoncer au plastique pour protéger l\'environnement et la santé publique.</p>',2),(466,707,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l\'avantage est avant tout économique. D\'une part, le livre numérique permet d\'économiser du papier, d\'autre part la version numérique d\'un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d\'augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(467,707,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le livre numérique remplacera-t-il le livre papier ? « Non », répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu\'on aime ou de l\'offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l\'odeur du neuf ou de l\'ancien… Il transmet beaucoup d\'émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(468,710,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Jean qui vit à la compagne favorise l\'achat des produits alimentaires directement à la ferme pour la bonne qualité quitte à payer un peu plus cher.</p>',1),(469,710,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Camille qui vit dans la ville préfère faire ses courses au supermarché pour la variété qu\'il propose et pour les prix abordables.</p>',2),(470,713,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les raisons qui poussent les parents à opter pour la scolarisation à domicile sont nombreuses. Elle donne la possibilité d\'adopter une pédagogie plus individualisée. On peut passer plus de temps sur les points sur lesquels l\'enfant bute ou lui proposer, à l\'occasion, des jeux éducatifs. L\'enfant gère son apprentissage à son rythme, il creuse les sujets qui le passionnent et ne subit pas la pression des autres élèves qui peuvent avancer plus au moins vite que lui. Autre avantage de l\'instruction en famille, une évolution différente. Avec l\'école à la maison, pas de notes qui peuvent parfois être décourageantes, mais un contrôle continu des connaissances, pas de stress dû aux évaluations et aux devoirs.</p>',1),(471,713,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le choix de la scolarisation à domicile représente un véritable défi et donc, quelques inconvénients à prendre en compte avant de se lancer. La scolarisation à domicile nécessite beaucoup de temps, une bonne organisation et elle a aussi un coût. Tout le matériel, les livres, les manuels, et les sorties sont à la charge des familles, et l\'un des deux parents est souvent amené à mettre entre parenthèses son emploi. Au total, l\'école à domicile coûte généralement plus cher qu\'une scolarisation dans le public. De plus, l\'enfant ne côtoie pas de camarades au quotidien, car l\'école à domicile ne permet pas à l\'enfant d\'entrer en interaction avec d\'autres enfants comme il le ferait dans un cadre scolaire classique.</p>',2),(472,716,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Quand on parle de vélo, on pense systématiquement à deux choses: sport et loisir. On oublie souvent que c\'est avant tout un mode de déplacement personnel et professionnel. En ville, c\'est un moyen de transport rapide et déstressant puisqu\'il permet d\'éviter les interminables embouteillages aux heures de pointe. Se rendre au travail tout en faisant du sport, histoire de joindre l\'utile à l\'agréable.</p>',1),(473,716,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Avec tous les accidents de la route observés annuellement, sortir son vélo pour se déplacer avec en ville peut être très dangereux. En effet, avec la densité importante de véhicules, le non-respect du Code de la route et le manque de pistes cyclables, pratiquer du vélo en zone urbaine présente de vrais risques d\'accident. De plus, faire du vélo de nos jours, c\'est s\'exposer à des gaz d\'échappement toxiques et nocifs pour la santé humaine (notamment le monoxyde de carbone…).</p>',2),(474,719,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas de frères et/ou de sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(475,719,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(476,722,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Grâce à l\'art, la curiosité des citadins est attisée dans l\'espace urbain. Que ce soit par une peinture ou un spectacle de rue, l\'atmosphère éphémère ainsi créée offre une interaction entre des artistes peu connus et un public hétéroclite, parfois peu habitué à côtoyer cette forme d\'art.Les villes d\'aujourd\'hui n\'ont plus la même vocation que celles d\'hier. Plus qu\'un lieu de résidence, la ville se réinvente, s\'enrichit de la diversité de sa population, s\'agence différemment et s\'ouvre sur le monde. Les espaces verts se créent et les murs se parent de couleurs grâce au street art. Cela débouche sur des lieux où la qualité de vie est privilégiée, tout en respectant la nature et l\'environnement.</p>',1),(477,722,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Mais à une plus large échelle, cela n\'est pas aussi évident. Les graffitis peuvent être perçus comme une dégradation de la communauté, une pollution visuelle ou une preuve de la rupture sociale.On le considèrent comme du vandalisme qui défigure les biens publics. Le débat sur les avantages et les inconvénients des graffitis fait rage parmi les artistes, les législateurs et les membres de la communauté.</p>',2),(478,725,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les objets connectés facilitent notre vie quotidienne. Ce sont des objets ou des équipements pilotés à distance à l\'aide d\'un téléphone portable ou par Internet, comme le système de chauffage ou la fermeture des portes. De plus, avec une montre ou un bracelet connecté, toutes nos activités peuvent être analysées. Un logiciel va mesurer le nombre de nos pas pour nous inciter à faire davantage d\'exercice. Un domaine où l\'on comprend mieux leur utilité est celui de la surveillance de la santé. Certains objets agissent comme un carnet de santé, toujours prêts à vous rappeler un rendez-vous chez le médecin ou des médicaments à prendre.</p>',1),(479,725,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il y aurait 50 milliards d\'objets connectés dans le monde : l\'alarme, le téléviseur, la caméra de surveillance, les volets, le détecteur de fumée. etc. Face à cette évolution, la question de la sécurité se pose. En effet, un pirate informatique peut prendre le contrôle d\'un objet connecté en quelques minutes. Ou encore, un cambrioleur pourrait vérifier grâce aux caméras de surveillance connectées d\'une habitation que les occupants sont absents. Il est aussi possible d\'entrer dans le système connecté d\'une voiture, et d\'en prendre les commandes à distance.</p>',2),(480,728,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>la gratuité des musées peut entraîner une sur fréquentation, ce qui nuit à la qualité de l\'expérience des visiteurs. De plus, cela puisse réduire les ressources financières des musées, affectant ainsi leur entretien et la préservation des œuvres. Un tarif réduit serait une meilleure solution pour rendre la culture accessible tout en soutenant les musées.</p>',1),(481,728,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La gratuité des musées est une excellente initiative. Cela rend la culture accessible à tous, indépendamment de leur situation financière. J\'ai pu visiter plusieurs musées gratuitement, ce qui m\'a permis d\'enrichir mes connaissances sans me soucier du coût. Pour moi, la gratuité des musées contribue à l\'éducation du public et au partage du patrimoine culturel.</p>',2),(482,731,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>les restaurants rapides proposent des plats équilibré et varié et ils respectent les normes d\'hygiènes et les variétés de produits qui sont bons et c\'est le client qui compose son menu, don il est responsable.</p>',1),(483,731,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>la restauration rapide est néfaste à la santé, elle cause des problèmes irréversible comme l\'obésité, etc.</p>',2),(484,734,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La location courte durée offre flexibilité et commodité pour les voyageurs. Elle permet de louer un logement pour une période de temps limitée, que ce soit pour des vacances ou un déplacement professionnel. Cela permet aux voyageurs de profiter d\'un hébergement confortable avec des équipements adaptés à leurs besoins, tout en évitant les engagements à long terme.</p>',1),(485,734,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La location courte durée peut parfois être coûteuse, en particulier dans les zones touristiques. De plus, la disponibilité peut être limitée, surtout pendant les périodes de forte demande. Il est donc important de planifier et de réserver à l\'avance pour obtenir les meilleurs résultats.</p>',2),(486,737,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Dans l\'école où j\'enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentent rassurés quant à la sécurité des enfants et que cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(487,737,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Je suis opposé à l\'installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l\'administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l\'école par tous, plutôt que de recourir aux caméras.</p>',2),(488,740,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le port de l\'uniforme développe un sentiment d\'appartenance à son établissement, et à la communauté des élèves. Il nourrit chez le jeune le sens du collectif et engendre souvent la fierté d\'appartenir à son établissement. De plus, il réduit la discrimination basée sur le style ou sur la classe sociale de l\'élève. En effet, l\'uniforme permet aux parents d\'économiser beaucoup d\'argent, ce ne sont pas tous les parents griffés ou de marques populaires. La mise en place d\'un code vestimentaire réduit donc les différences entre les classes sociales.</p>',1),(489,740,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le port de l\'uniforme étouffe et écrase la personnalité des garçons. Ils ne peuvent pas s\'habiller comme ils le veulent, en aucune circonstance. De l\'autre côté de l\'échelle (chez les pros) il y a des gens qui préfèreraient, pour eux-mêmes et leurs enfants, avoir la possibilité de s\'exprimer à travers l\'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers I \'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers la mode, se démarquer de la foule grâce à un accessoire ou un vêtement particulier se retrouveront déçus et emprisonnés dans l\'uniforme.</p>',2),(490,743,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(491,743,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(492,746,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Jean : Je suis fermement convaincu que l\'intégration des nouvelles technologies dans les écoles est cruciale pour préparer les élèves à un avenir numérique. Je pense que l\'usage des tablettes et des ordinateurs stimule non seulement l\'engagement des élèves mais enrichit également leur expérience éducative en leur offrant un accès facile à une variété de ressources, encourageant ainsi leur créativité et autonomie.</p>',1),(493,746,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Sara : Je suis sceptique quant à l\'usage intensif des technologies dans l\'enseignement. Je crois que cela peut réduire les interactions humaines essentielles et favoriser une dépendance préoccupante aux écrans. À mon avis, les méthodes d\'enseignement traditionnelles et le contact direct entre enseignants et élèves restent indispensables pour un développement équilibré et complet des compétences des jeunes.</p>',2),(494,749,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivre les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(495,749,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(496,752,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>À la rentrée, le nombre d\'élèves inscrits dans des écoles privées a augmenté en France. Le succès des établissements privés n\'est pas directement lié aux bons résultats scolaires de leurs élèves. C\'est la réputation de ces lieux qui explique un tel enthousiasme. Aux yeux de nombreux parents, les élèves y sont mieux encadrés, mieux surveillés et les professeurs sont plus présents. Les parents sont aussi rassurés parce que les classes sont homogènes : elles accueillent généralement des élèves de milieux sociaux favorisés. En effet, les études dans ces établissements sont payantes, ce qui n\'est pas le cas dans les écoles publiques.</p>',1),(497,752,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Dans les collèges privés, il y a peu d\'élèves de milieux sociaux défavorisés. Comme les études dans ces établissements sont payantes, certaines catégories de population en sont exclues. Ce système qui oppose écoles publiques et écoles privées ne facilite pas la mixité sociale. Ainsi, les élèves du privé ont rarement l\'occasion de rencontrer d\'autres jeunes issus de milieux sociaux moins favorisés qu\'eux et inversement. Ce modèle scolaire reproduit les inégalités sociales et renforce le sentiment d\'exclusion de certains jeunes.</p>',2),(498,755,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(499,755,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(500,758,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(501,758,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(502,761,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le supermarché est très pratique ; on y trouve une grande variété de produits, todos à portée de main. Vous pouvez garer votre voiture dans le parking et faire le tour des rayons pour acheter tout ce dont vous avez besoin : fruits, légumes, fromages, viandes, boissons... De plus, les supermarchés offrent plusieurs marques pour un même produit, tout en proposant régulièrement des promotions et des remises.</p>',1),(503,761,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>ASSOCIATION POUR LA SAUVEGARDE DES PETITS COMMERCES</p>\r\n                        <p>Le défi « Février sans supermarché » a été créé pour limiter la superpuissance des supermarchés et, par conséquent, permettre aux petits commerces de survivre et de réaliser des chiffres d\'affaires plus conséquents. Ce défi consiste à boycotter les supermarchés pendant une durée d\'un mois, en faisant toutes ses courses dans les épiceries de quartier. Le client aura tout à gagner : il bénéficiera non seulement de produits frais de meilleure qualité, mais aura également l\'opportunité de papoter avec les voisins.</p>',2),(504,764,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je vais bientôt avoir 22 ans et j\'habite toujours chez mes parents. Mon père et ma mère restent autoritaires avec moi, même si je suis majeure. Quand j\'étais mineure, je n\'avais pas le droit de dormir dehors, ni même de dépasser 21h lorsque je sortais avec des amies. Maintenant, peu de choses ont changé ; certes, j\'ai le droit de veiller plus tard la nuit, mais ma mère ne cesse de m\'appeler sur mon téléphone portable jusqu\'à ce que je sois de retour.</p>',1),(505,764,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les parents ont parfois peur d\'être trop sévères avec leurs enfants. Ils craignent, qu\'à cause d\'un excès d\'autorité, leurs enfants ne s\'épanouissent pas et manquent plus tard de personnalité. Même si les parents acceptent, par amour, tout ce dont leurs enfants demandent, cela pourrait avoir des effets négatifs lorsqu\'ils passent à l\'âge adulte. En effet, pour vivre en communauté, il y a certaines règles à respecter.</p>',2),(506,767,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(507,767,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits.</p>\r\n                        <p>Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués.</p>',2),(508,770,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(509,770,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(510,773,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Avec l\'avancée technologique et les produits high-tech qui envahissent de plus en plus notre quotidien, nos enfants oublient la lecture et s\'intéressent davantage aux jeux vidéo, aux sports, à la musique... Contrairement à nous les adultes, dont beaucoup d\'entre-nous ont lu des milliers de pages, la génération actuelle est toujours occupée par les réseaux sociaux et le gaming ou prennent du plaisir à pratiquer du sport qui attirent davantage de jeunes grâce aux stars internationales du football, du tennis, de l\'athlétisme... alors avec tout ça, pourquoi devons-nous forcer les enfants à lire un bouquin ? Et comme le dit un proverbe, \'\' le goût de la lecture ne peut pas s\'imposer\'\'... il faut laisser l\'enfant choisir ce qu\'il veut lire et surtout ne pas l\'obliger à lire quand il n\'a pas envie.</p>',1),(511,773,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>L\'amour de la lecture se transmet de génération en génération bien que, ces dernières années, on ne trouve plus beaucoup de bouquins entre les mains des enfants, laissant la place aux smartphones et aux tablettes. En apprenant à lire régulièrement, l\'enfant acquiert le langage plus aisément tout en développant sa capacité d\'audition et de concentration. De plus, et pour prendre du plaisir ensemble, les parents peuvent consacrer quotidiennement 10 minutes à leurs enfants pour lire des bouquins ; une activité qui renforcera à coup sûr la complicité parent/enfant.</p>',2),(512,776,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(513,776,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits.<br><br>\r\n                        Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués.</p>',2),(514,779,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer plus de temps à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress, améliorant ainsi leur productivité globale.</p>',1),(515,779,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        La réduction du temps de travail peut bénéficier aux entreprises en diminuant l\'absentéisme et en améliorant la rétention des employés. Avec des horaires plus flexibles, les employés sont souvent plus motivés et engagés. Cependant, cela nécessite une bonne organisation et une adaptation des processus pour maintenir l\'efficacité et répondre aux besoins de l\'entreprise.</p>',2),(516,782,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d\'hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(517,782,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l\'environnement.</p>',2),(518,785,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        Jean qui vit à la compagne favorise l\'achat des produits alimentaires directement à la ferme pour la bonne qualité quitte à payer un peu plus cher.</p>',1),(519,785,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        Camille qui vit dans la ville préfère faire ses courses au supermarché pour la variété qu\'il propose et pour les prix abordables.</p>',2),(520,788,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        Jean : Je suis fermement convaincu que l\'intégration des nouvelles technologies dans les écoles est cruciale pour préparer les élèves à un avenir numérique. Je pense que l\'usage des tablettes et des ordinateurs stimule non seulement l\'engagement des élèves mais enrichit également leur expérience éducative en leur offrant un accès facile à une variété de ressources, encourageant ainsi leur créativité et autonomie.</p>',1),(521,788,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        Sara : Je suis sceptique quant à l\'usage intensif des technologies dans l\'enseignement. Je crois que cela peut réduire les interactions humaines essentielles et favoriser une dépendance préoccupante aux écrans. À mon avis, les méthodes d\'enseignement traditionnelles et le contact direct entre enseignants et élèves restent indispensables pour un développement équilibré et complet des compétences des jeunes.</p>',2),(522,791,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        \"Je suis de ceux qui n\'arrivent pas à comprendre comment l\'on peut prendre du plaisir à tuer des animaux. Je suis de ceux qui n\'arrivent pas à comprendre comment on peut prétendre aimer la nature alors qu\'on la détruit\"<br><br>\r\n                        Gala 29 ans.</p>',1),(523,791,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        \"Les gens chassent pour différentes raisons : la subsistance, le commerce, la conversation et l\'aménagement de la faune, la protection de la propriété, l\'exercice, le loisir et le prestige.\"<br><br>\r\n                        David, Journaliste de la FRM.</p>',2),(524,794,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                        Grâce à l\'art, la curiosité des citadins est attisée dans l\'espace urbain. Que ce soit par une peinture ou un spectacle de rue, l\'atmosphère éphémère ainsi créée offre une interaction entre des artistes peu connus et un public hétéroclite, parfois peu habitué à côtoyer cette forme d\'art. Les villes d\'aujourd\'hui n\'ont plus la même vocation que celles d\'hier. Plus qu\'un lieu de résidence, la ville se réinvente, s\'enrichit de la diversité de sa population, s\'agence différemment et s\'ouvre sur le monde. Les espaces verts se créent et les murs se parent de couleurs grâce au street art. Cela débouche sur des lieux où la qualité de vie est privilégiée, tout en respectant la nature et l\'environnement.</p>',1),(525,794,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                        Mais à une plus large échelle, cela n\'est pas aussi évident. Les graffitis peuvent être perçus comme une dégradation de la communauté, une pollution visuelle ou une preuve de la rupture sociale. On les considère comme du vandalisme qui défigure les biens publics. Le débat sur les avantages et les inconvénients des graffitis fait rage parmi les artistes, les législateurs et les membres de la communauté.</p>',2),(526,797,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                Les objets connectés facilitent notre vie quotidienne. Ce sont des objets ou des équipements pilotés à distance à l\'aide d\'un téléphone portable ou par Internet, comme le système de chauffage ou la fermeture des portes. De plus, avec une montre ou un bracelet connecté, toutes nos activités peuvent être analysées. Un logiciel va mesurer le nombre de nos pas pour nous inciter à faire davantage d\'exercice. Un domaine où l\'on comprend mieux leur utilité est celui de la surveillance de la santé. Certains objets agissent comme un carnet de santé, toujours prêts à vous rappeler un rendez-vous chez le médecin ou des médicaments à prendre.</p>',1),(527,797,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                Il y aurait 50 milliards d\'objets connectés dans le monde : l\'alarme, le téléviseur, la caméra de surveillance, les volets, le détecteur de fumée, etc. Face à cette évolution, la question de la sécurité se pose. En effet, un pirate informatique peut prendre le contrôle d\'un objet connecté en quelques minutes. Ou encore, un cambrioleur pourrait vérifier grâce aux caméras de surveillance connectées d\'une habitation si les occupants sont absents. Il est aussi possible d\'entrer dans le système connecté d\'une voiture et d\'en prendre les commandes à distance.</p>',2),(528,800,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Les restaurants rapides proposent des plats équilibrés et variés, et ils respectent les normes d\'hygiène et les variétés de produits qui sont bons, et c\'est le client qui compose son menu, donc il en est responsable.</p>',1),(529,800,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    La restauration rapide est néfaste à la santé, elle cause des problèmes irréversibles comme l\'obésité, etc.</p>',2),(530,803,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    La gratuité des musées peut entraîner une surfréquentation, ce qui nuit à la qualité de l\'expérience des visiteurs. De plus, cela peut réduire les ressources financières des musées, affectant ainsi leur entretien et la préservation des œuvres. Un tarif réduit serait une meilleure solution pour rendre la culture accessible tout en soutenant les musées.</p>',1),(531,803,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    La gratuité des musées est une excellente initiative. Cela rend la culture accessible à tous, indépendamment de leur situation financière. J\'ai pu visiter plusieurs musées gratuitement, ce qui m\'a permis d\'enrichir mes connaissances sans me soucier du coût. Pour moi, la gratuité des musées contribue à l\'éducation du public et au partage du patrimoine culturel.</p>',2),(532,806,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    D\'après le site síestepourtous.com, une micro-sieste permettrait d\'augmenter la productivité et la créativité des travailleurs de 35%, ce qui est un avantage considérable pour l\'employé et l\'employeur. Aussi, la sieste au travail permettrait d\'augmenter la mémoire et donc la concentration. Un salarié reposé ne penserait plus à dormir et serait davantage disponible pour ses missions. Grâce à la sieste au bureau, le stress et les risques cardiaques diminueraient.</p>',1),(533,806,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Bien que les effets positifs d\'une power nap aient été scientifiquement prouvés, il existe encore des personnes qui s\'y opposent et y voient des inconvénients. La sieste au travail est assez difficile en termes de faisabilité. En effet ce n\'est pas dans les moyens de toutes les entreprises de mettre en place des lits et des salles dédiées à cette pratique. Lorsqu\'une entreprise veut mettre en place un temps de repos dans son organisation, elle n\'est pas tout à fait libre de faire selon son bon vouloir. L\'entreprise devra se conformer à certaines règles : la mise à disposition d\'un local dédié et de matériel, la prévention des situations de harcèlement des employés lors de la sieste, l\'égalité de traitement entre salariés, l\'établissement d\'une charte, etc.</p>',2),(534,809,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Grâce à la livraison en entreprise, les employés bénéficieront d\'un gain de temps notable. Il n\'est plus question d\'aller sortir loin du lieu de travail pour trouver de quoi manger. En complément, l\'argent et l\'énergie économisée permettent d\'être encore plus efficace au travail. Sans pour autant mettre fin à une session importante liée au travail, le repas sera déjà prêt et pourra attendre la fin d\'une conférence, d\'une réunion ou d\'un rendez-vous. Il s\'agit d\'une véritable solution dédiée aux entreprises ayant une activité intense et qui requiert la présence continue de leurs employés.\r\n                    Et en ce qui concerne les inconvénients ?</p>',1),(535,809,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l\'attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(536,812,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d\'offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d\'information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(537,812,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d\'autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d\'un sport. Il est important de faire preuve de discernement et de réguler l\'exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d\'apprentissage et de divertissement.</p>',2),(538,815,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Des études ont montré que certaines zones du cerveau de l\'adulte peuvent être développées en jouant aux jeux vidéo. Ainsi, il peut être intéressant de jouer aux jeux vidéo, car ils permettent, par exemple, d\'améliorer la capacité d\'analyse, la capacité à faire des choix et la rapidité de réaction. C\'est une bonne nouvelle car la répartition des joueurs par âge montre que 83% des joueurs sont des adultes. Cependant, il convient de rester prudent car certains jeux vidéos ne favorisent pas ce type d\'amélioration sur le cerveau.</p>',1),(539,815,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Pendant trois ans, des enfants âgés de 8 à 17 ans ont participé à une étude sur les jeux vidéo. Les résultats de cette étude montrent que les enfants qui jouent beaucoup aux jeux vidéo sont plus violents, plus nerveux et plus stressés que ceux qui ne jouent pas ou peu. Ceux qui jouent beaucoup ont également moins de bons résultats à l\'école. Il est donc conseillé aux parents d\'être vigilants et de limiter l\'usage de ces jeux par leurs enfants.</p>',2),(540,818,1,'Document 1 :','<p>Les amitiés entre collègues au travail peuvent être extrêmement bénéfiques. Elles favorisent un climat de travail agréable et une ambiance positive au sein de l’équipe. Avoir des amis parmi ses collègues permet de renforcer les liens professionnels et de créer un sentiment de camaraderie. Cela peut contribuer à une meilleure communication, une collaboration plus étroite et une résolution plus efficace des problèmes. De plus, partager des moments de convivialité en dehors du travail, comme des déjeuners ou des activités après le bureau peut renforcer les liens et créer une dynamique de groupe solide.</p>',1),(541,818,2,'Document 2 :','<p>Il est important de trouver un équilibre entre amitié et professionnalisme au travail. Les amitiés excessivement proches peuvent parfois créer des tensions ou des conflits lorsque des décisions professionnelles doivent être prises. De plus, les amitiés exclusives entre certains collègues peuvent exclure les autres membres de l’équipe, ce qui peut nuire à la cohésion et à la collaboration. Il est essentiel de maintenir des limites claires et de veiller à ce que les amitiés ne compromettent pas le professionnalisme, la hiérarchie ou la productivité au sein de l’organisation.</p>',2),(542,821,1,'Document 1 :','<p>Franck soutient l’utilisation limitée du plastique, soulignant son importance dans de nombreux secteurs, notamment les secteurs médical et alimentaire. Pour lui, le plastique est vital pour la conservation des aliments et la stérilisation des équipements médicaux. Il prône une utilisation responsable et le recyclage, mais reconnaît que certains usages du plastique sont indispensables pour la société moderne.</p>',1),(543,821,2,'Document 2 :','<p>Amicha s’oppose fermement à l’utilisation du plastique, mettant en avant son impact environnemental dévastateur. Elle soutient que les déchets plastiques polluent les océans et les écosystèmes, causant des dommages irréparables. Amicha milite pour des alternatives écologiques et durables, insistant sur l’urgence de renoncer au plastique pour protéger l’environnement et la santé publique.</p>',2),(544,824,1,'Document 1 :','<p>De nos jours, les journées passent très vite car nous sommes tout le temps pris par un rythme de vie effréné : travail, enfants, loisirs… Dès lors, beaucoup d’entre nous préfèrent et favorisent des habitudes alimentaires basées essentiellement sur des repas tout faits à emporter ou à consommer sur place. Prenons l’exemple d’Annette, une jeune femme de 28 ans qui se consacre énormément à son travail et qui aime dîner au restaurant tout en passant de bons moments avec ses amis. Cela lui permet de manger sainement sans avoir à passer des heures dans la cuisine après une rude journée de travail. Ce mode de vie lui convient en tant que célibataire, lui permettant de découvrir de nouveaux restaurants bien notés, de faire de nouvelles connaissances, et d’éviter de longues soirées seule devant sa télévision. Et ceci est vrai même pour les plus jeunes.</p>',1),(545,824,2,'Document 2 :','<p>Les fast-foods et la restauration en général ont conduit beaucoup d’entre nous à adopter de mauvaises habitudes alimentaires, basées sur des plats rapides, déséquilibrés, et riches en calories et en graisses. Heureusement, certaines familles tiennent encore bon et choisissent de manger chez elles tout en faisant des économies. Prenons l’exemple de Jeanne, une femme mariée de 45 ans qui préfère manger à la maison avec son mari et ses cinq enfants. En cuisinant elle-même, elle sait ce qu’elle met dans son assiette tout en préservant son budget. Cette caissière, qui travaille dans une grande surface, préfère réaliser elle-même ses recettes car, non seulement ses moyens financiers sont limités, mais elle prend également un plaisir fou à cuisiner pour sa famille.</p>',2),(546,830,1,'Document 1 :','<p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l’avantage est avant tout économique. D’une part, le livre numérique permet d’économiser du papier, d’autre part la version numérique d’un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d’augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(547,830,2,'Document 2 :','<p>Le livre numérique remplacera-t-il le livre papier ? « Non », répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu’on aime ou de l’offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l’odeur du neuf ou de l’ancien… Il transmet beaucoup d’émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(548,836,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>De plus en plus d\'écoles décident de mettre en place un menu sans viande dans les cantines, au moins deux fois par semaine. Certaines études ont montré que les enfants consomment trop de protéines animales. C\'est donc une question de santé : les écoles ont choisi de remplacer la viande par d\'autres produits (soja, céréales, légumes), moins gras et utiles à la croissance des enfants. Ces menus sans viandes à la cantine reviennent moins cher aux familles. Cette idée plaît beaucoup aux parents comme aux enfants.</p>',1),(549,836,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La décision de supprimer la viande dans les cantines ne plaît pas à tout le monde. En effet, c\'est un produit cher : la cantine est le seul endroit où les enfants de familles en difficulté peuvent manger. Les producteurs locaux de viande sont également mécontents : une partie de leur production est réservée aux cantines, il s\'agit donc d\'une perte financière. Enfin, beaucoup d\'enfants interrogés déclarent tout de même préférer les steaks de bœuf aux steaks de soja qui, selon eux, ont peu de goût.</p>',2),(550,839,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La gratuité des musées peut entraîner une sur fréquentation, ce qui nuit à la qualité de l\'expérience des visiteurs. De plus, cela peut réduire les ressources financières des musées, affectant ainsi leur entretien et la préservation des œuvres. Un tarif réduit serait une meilleure solution pour rendre la culture accessible tout en soutenant les musées.</p>',1),(551,839,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La gratuité des musées est une excellente initiative. Cela rend la culture accessible à tous, indépendamment de leur situation financière. J\'ai pu visiter plusieurs musées gratuitement, ce qui m\'a permis d\'enrichir mes connaissances sans me soucier du coût. Pour moi, la gratuité des musées contribue à l\'éducation du public et au partage du patrimoine culturel.</p>',2),(552,842,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Dans l\'école où j\'enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentent rassurés quant à la sécurité des enfants et que cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(553,842,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Je suis opposé à l\'installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l\'administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l\'école par tous, plutôt que de recourir aux caméras.</p>',2),(554,845,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(555,845,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(556,848,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p><strong>Opinion 1 :</strong></p>\r\n                    <p>\"Je suis en faveur des distributeurs de boissons dans les lycées. Premièrement, ils offrent une commodité supplémentaire pour les élèves, notamment pour ceux qui n\'ont pas le temps de passer à la cafétéria pendant les pauses. Deuxièmement, s\'ils sont bien gérés, ces distributeurs peuvent offrir une gamme de boissons saines, comme de l\'eau, du jus de fruits pur et des boissons aux fruits sans sucre ajouté. Ces distributeurs peuvent être une source de revenus supplémentaires pour l\'école, qui peut être réinvestie dans l\'amélioration des infrastructures ou des programmes scolaires.\"</p>',1),(557,848,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p><strong>Opinion 2 :</strong></p>\r\n                    <p>\"Je suis contre l\'installation de distributeurs de boissons dans les lycées. Ma principale préoccupation est liée à la santé des élèves. Malheureusement, beaucoup de ces distributeurs sont remplis de boissons sucrées et de sodas qui contribuent à l\'obésité infantile et à d\'autres problèmes de santé comme le diabète. Même les jus de fruits, qui peuvent sembler sains, contiennent souvent beaucoup de sucre. Les écoles devraient être des lieux qui encouragent des habitudes alimentaires saines et je crains que la présence de ces distributeurs n\'encourage une consommation excessive de boissons sucrées.\"</p>',2),(558,851,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p><strong>Opinion 1 : Alexandre, un conseiller d\'orientation</strong></p>\r\n                    <p>\"Je suis fermement pour le travail des jeunes pendant les vacances. C\'est une excellente occasion d\'acquérir des compétences pratiques, d\'apprendre à travailler en équipe et de découvrir différentes industries. Les jeunes peuvent gagner de l\'argent qu\'ils peuvent économiser pour l\'avenir ou utiliser pour financer des activités ou des loisirs. De plus, le fait d\'avoir une expérience de travail sur leur CV peut leur donner un avantage lorsqu\'ils postulent pour des emplois ou des stages à l\'avenir. Les vacances d\'été sont longues et il y a amplement de temps pour se reposer et travailler.\"</p>',1),(559,851,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p><strong>Opinion 2 : Élise, une psychologue pour adolescents</strong></p>\r\n                    <p>\"Je suis contre l\'idée que les jeunes doivent travailler pendant leurs vacances. Les adolescents sont déjà sous une énorme pression pendant l\'année scolaire avec les études, les examens et les activités parascolaires. Les vacances doivent être une période pour eux de se détendre, de se décompresser et de poursuivre des intérêts personnels. Les forcer à travailler pourrait contribuer au stress et à l\'épuisement. Il est également important pour les jeunes de disposer de temps non structuré pour explorer leur créativité, passer du temps avec leurs amis et leur famille, et tout simplement être des enfants. Le travail peut attendre.\"</p>',2),(560,854,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de tiempo libre pour mieux vivre.</p>',1),(561,854,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(562,857,1,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les animaux sauvages ne devraient pas être confinés dans des zoos, car cela ne correspond pas à leur habitat naturel. Il décrit les zoos comme des prisons pour les animaux, citant l\'exemple d\'ours polaires maintenus dans des environnements où la température atteint 15 degrés. Enfin, les animaux nécessitent un environnement naturel et la liberté.</p>',1),(563,860,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Certaines personnes trouvent la publicité ennuyeuse, mais, à mon avis, elle est indispensable pour le commerce et les entreprises. Grâce à la publicité, on fait connaître un produit ou un service. Et puis, parfois, elles sont drôles ! J\'aime bien les écouter quand je suis en voiture. Cela me permet aussi d\'être informé des nouveautés et des promotions. Personnellement, j\'adore comparer les articles : je peux ainsi faire beaucoup d\'économies sur mes achats. Enfin, beaucoup de personnes jouent à des jeux gratuits sur leur téléphone : sans publicité, ces jeux seraient tous payants. Quentin, 28 ans.</p>',1),(564,860,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La publicité est présente partout dans notre vie de tous les jours : journaux, radios, télévision, téléphone, Internet... Par exemple, sur certaines chaînes de télévision, les émissions sont coupées par la publicité et c\'est agaçant. Puis, recevoir des dizaines de kilos de papier de publicité par an dans la boîte aux lettres, ce n\'est pas très respectueux de l\'environnement ! Je pense qu\'il est nécessaire de faire voter une loi pour réduire les publicités par courrier et à la télévision. Si la publicité était plus discrète, elle serait plus appréciée. Estelle, 35 ans.</p>',2),(565,863,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les achats en ligne ont des avantages comme gagner de temps consommateurs les et de trouvent l\'argent. les facilement, disponibilité 24/24, produits provenant de tout le monde etc.</p>',1),(566,863,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les magazines nous donne la possibilité d\'avoir un contact humain et relation avec les vendeurs + possibilité de voir et de toucher ce qu\'on veut ... les consommateurs favorisent l\'achat traditionnel, visiter des magasins le permette d\'échanger des achats insatisfaisants et de se se communiquer avec les vendeurs.</p>',2),(567,866,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(568,866,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures,opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, ...)</p>',2),(569,869,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(570,869,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(571,872,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>(Marie 58 ans): J\'ai pris l\'habitude, depuis des années maintenant, de donner un peu de mon temps et de mon argent afin d\'aider les personnes vivant dans la précarité extrême; surtout ceux qui vivent sans abri en période hivernale. Pour moi, c\'est un devoir d\'aider et de contribuer afin que ces personnes puissent vivre le plus normalement possible. En assistant des pauvres ou des associations, on se sent utile au sein d\'une société qui devient de plus en plus impitoyable.</p>',1),(572,872,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>(Paul 63 ans ) : Pour aider les personnes vivant dans la précarité, on doit s\'investir davantage dans les associations caritatives. Personnellement, c\'est ce que je fais; je suis bénévole dans une association située dans mon quartier. Elle a pour principal but, aider les sans-abris à trouver un logement et un travail afin qu\'ils vivent le plus normalement possible. Cette action est plus bénéfique à long terme car elle permet de les rendre autonomes.</p>',2),(573,875,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les enfants, jusqu\'à l\'âge de l\'adolescence, jouent d\'une manière régulière aux jeux vidéo et à force, ils peuvent développer des pensées négatives et des comportements agressifs. En effet, une étude récente, menée sur des enfants âgés de 9 à 18 ans jouant fréquemment aux jeux vidéo, a révélé que le fait de jouer à des jeux de violence augmente considérablement un comportement agressif. Et selon Diégo Gentil, ce phénomène est inévitable, quel que soit le degré de vigilance des parents !</p>',1),(574,875,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>On parle tout le temps des effets négatifs des jeux vidéo, mais ces derniers peuvent également avoir quelques avantages pour le fonctionnement du cerveau et pour la santé d\'une manière générale. Si on prend, par exemple, leur apport pour le cerveau, les jeux vidéo permettent d\'améliorer plusieurs fonctions cognitives telles que l\'amélioration de la concentration, de la réaction et de la capacité d\'analyser. Ceci peut paraître évident, dans la mesure où lorsqu\'on y joue, on doit toujours trouver des solutions à des situations plus au moins complexes (surtout pour les jeux de stratégie).</p>',2),(575,878,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d\'hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(576,878,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l\'environnement.</p>',2),(577,881,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le port de l\'uniforme étouffe et écrase la personnalité des garçons. Ils ne peuvent s\'habiller comme ils veulent, en aucune circonstance. De l\'autre coté de l\'échelle (chez les pros) il y a des gens qui préféraient pour eux-mêmes et leurs enfants, avoir la possibilité de s\'exprimer à travers l\'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers la mode, se démarquer de la foule grâce à un accessoire ou un vêtement particulier, se retrouveront déçus et emprisonnés dans l\'uniforme.</p>',1),(578,881,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le port de l\'uniforme développe un sentiment d\'appartenance à son établissement, et à la communautés des élèves. Il nourrit chez le jeune le sens du collectif et engendre souvent la fierté d\'appartenir à son établissement. De plus, il réduit la discrimination basée sur le style ou sur la classe sociale de l\'élève. En effet, l\'uniforme permet aux parents d\'économiser beaucoup d\'argents, ce ne sont pas tous les parents qui peuvent payer à leurs enfants de beaux vêtements griffés ou de marques populaires. La mise en place d\'un code vestimentaire réduit donc les différences entre les classes sociales.</p>',2),(579,884,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>De nos jours, il y a de plus en plus de caméras de surveillance dans les villes. La vidéosurveillance est appréciée par les Français car cela leur donne un sentiment de sécurité. D\'après un sondage, 75% d\'entre eux sont pour le développement de la vidéosurveillance. Ils seraient d\'accord pour être filmés, mais seulement dans l\'espace public: la rue, les magasins ou encore les transports. Cependant, ils refusent d\'être surveillés par leur employeur. En France, peu de caméras de vidéosurveillance sont installées sur le lieu de travail.</p>',1),(580,884,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Certaines enquêtes montrent que la vidéo surveillance coûte cher et que ses résultats sont insuffisants. D\'une part, la présence des caméras est facile à remarquer. Par conséquent, la vidéo surveillance est inutile pour éviter les vols, la consommation de drogue et la violence dans les villes. D\'autre part, l\'utilisation de vidéo surveillance demande beaucoup de personnel. Une étude allemande montre que sept personnes par caméra sont nécessaires pour analyser les informations.</p>',2),(581,887,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Grâce à la livraison en entreprise, les employés bénéficieront d\'un gain de temps notable. Il n\'est plus question d\'aller sortir loin du lieu de travail pour trouver de quoi manger. En complément, l\'argent et l\'énergie économisée permettent d\'être encore plus efficace au travail. Sans pour autant mettre fin à une session importante liée au travail, le repas sera déjà prêt et pourra attendre la fin d\'une conférence, d\'une réunion ou d\'un rendez-vous. Il s\'agit d\'une véritable solution dédiée aux entreprises ayant une activité intense et qui requiert la présence continue de leurs employés.</p>',1),(582,887,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l\'attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(583,890,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(584,890,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(585,893,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je suis de ceux qui n\'arrivent pas à comprendre comment l\'on peut prendre du plaisir à tuer des animaux. Je suis de ceux qui n\'arrivent pas à comprendre comment on peut prétendre aimer la nature alors qu\'on la détruit\"</p>\r\n                        <p>Gala 29 ans</p>',1),(586,893,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>\"Les gens chassent pour différentes raisons : la subsistance, le commerce, la conversation et l\'aménagement de la faune, la protection de la propriété, l\'exercice, le loisir et le prestige.\"</p>\r\n                        <p>David, Journaliste de la FRM</p>',2),(587,896,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(588,896,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits.</p>\r\n                        <p>Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués.</p>',2),(589,899,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Opinion 1 : Stéphane, entrepreneur</p>\r\n                        <p>« Je suis convaincu que le travail est absolument favorable pour l\'individu et la société. Le travail permet non seulement d\'assurer son propre moyen de subsistance, mais également de contribuer au développement économique de la société. De plus, il favorise l\'autonomie et la confiance en soi, encourage le sens des responsabilités et offre une opportunité d\'épanouissement personnel et professionnel. Il peut même aider à forger notre identité et notre place dans la société. »</p>',1),(590,899,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Opinion 2 : Laura, sociologue</p>\r\n                        <p>« Le travail, dans sa forme actuelle, peut avoir des aspects défavorables. Dans de nombreux cas, le travail est associé à un stress intense, à des horaires rigides et à un déséquilibre entre la vie professionnelle et la vie privée. Il peut être une source d\'épuisement professionnel, surtout lorsque la charge de travail est excessive et que la reconnaissance est faible. De plus, certaines formes de travail peuvent être aliénantes, lorsque les travailleurs ne se sentent pas impliqués ou valorisés dans ce qu\'ils font. Il est donc essentiel de repenser nos rapports au travail pour en faire une expérience plus équilibrée et enrichissante. »</p>',2),(591,902,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Opinion 1 : Alexandre, un conseiller d\'orientation</p>\r\n                        <p>« Je suis fermement pour le travail des jeunes pendant les vacances. C\'est une excellente occasion d\'acquérir des compétences pratiques, d\'apprendre à travailler en équipe et de découvrir différentes industries. Les jeunes peuvent gagner de l\'argent qu\'ils peuvent économiser pour l\'avenir ou utiliser pour financer des activités ou des loisirs. De plus, le fait d\'avoir une expérience de travail sur leur CV peut leur donner un avantage lorsqu\'ils postulent pour des emplois ou des stages à l\'avenir. Les vacances d\'été sont longues et il y a amplement de temps pour se reposer et travailler.</p>',1),(592,902,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Opinion 2 : Élise, une psychologue pour adolescents</p>\r\n                        <p>« Je suis contre l\'idée que les jeunes doivent travailler pendant leurs vacances. Les adolescents sont déjà sous une énorme pression pendant l\'année scolaire avec les études, les examens et les activités parascolaires. Les vacances doivent être une période pour eux de se détendre, de se décompresser et de poursuivre des intérêts personnels. Les forcer à travailler pourrait contribuer au stress et à l\'épuisement. Il est également important pour les jeunes de disposer de temps non structuré pour explorer leur créativité, passer du temps avec leurs amis et leur famille, et tout simplement être des enfants. Le travail peut attendre. »</p>',2),(593,905,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Certains postes sont majoritairement occupés par des hommes. Au Québec, l\'égalité entre les femmes et les hommes est respectée, les femmes peuvent les métiers réservés aux hommes tel que les postes de direction.</p>',1),(594,905,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Malgré les efforts pour imposer la parité à tous les postes dans les entreprises et les collectivités, il y a, dans les faits, des métiers où les femmes sont largement majoritaires tels que : les sage-femmes. De plus, les femmes ne doivent pas faire les métiers d\'homme, car ils doivent prendre soin de ses enfants.</p>',2),(595,908,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Dans l\'école où j\'enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentent rassurés quant à la sécurité des enfants et que cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(596,908,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Je suis opposé à l\'installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l\'administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l\'école par tous, plutôt que de recourir aux caméras.</p>',2),(597,911,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(598,911,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits.</p>\r\n                        <p>Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués.</p>',2),(599,914,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer plus de temps à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress, améliorant ainsi leur productivité globale.</p>',1),(600,914,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La réduction du temps de travail peut bénéficier aux entreprises en diminuant l\'absentéisme et en améliorant la rétention des employés. Avec des horaires plus flexibles, les employés sont souvent plus motivés et engagés. Cependant, cela nécessite une bonne organisation et une adaptation des processus pour maintenir l\'efficacité et répondre aux besoins de l\'entreprise.</p>',2),(601,917,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Des études ont montré que certaines zones du cerveau de l\'adulte peuvent être développées en jouant aux jeux vidéo. Ainsi, il peut être intéressant de jouer aux jeux vidéo, car ils permettent, par exemple, d\'améliorer la capacité d\'analyse, la capacité à faire des choix et la rapidité de réaction. C\'est une bonne nouvelle car la répartition des joueurs par âge montre que 83% des joueurs sont des adultes. Cependant, il convient de rester prudent car certains jeux vidéos ne favorisent pas ce type d\'amélioration sur le cerveau.</p>',1),(602,917,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Pendant trois ans, des enfants âgés de 8 à 17 ans ont participé à une étude sur les jeux vidéo. Les résultats de cette étude montrent que les enfants qui jouent beaucoup aux jeux vidéo sont plus violents, plus nerveux et plus stressés que ceux qui ne jouent pas ou peu. Ceux qui jouent beaucoup ont également moins de bons résultats à l\'école. Il est donc conseillé aux parents d\'être vigilants et de limiter l\'usage de ces jeux par leurs enfants.</p>',2),(603,920,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le port de l\'uniforme étouffe et écrase la personnalité des garçons. Ils ne peuvent s\'habiller comme ils veulent, en aucune circonstance. De l\'autre coté de l\'échelle (chez les pros) il y a des gens qui préféraient pour eux-mêmes et leurs enfants, avoir la possibilité de s\'exprimer à travers l\'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers la mode, se démarquer de la foule grâce à un accessoire ou un vêtement particulier, se retrouveront déçus et emprisonnés dans l\'uniforme.</p>',1),(604,920,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le port de l\'uniforme développe un sentiment d\'appartenance à son établissement, et à la communautés des élèves. Il nourrit chez le jeune le sens du collectif et engendre souvent la fierté d\'appartenir à son établissement. De plus, il réduit la discrimination basée sur le style ou sur la classe sociale de l\'élève. En effet, l\'uniforme permet aux parents d\'économiser beaucoup d\'argents, ce ne sont pas tous les parents qui peuvent payer à leurs enfants de beaux vêtements griffés ou de marques populaires. La mise en place d\'un code vestimentaire réduit donc les différences entre les classes sociales.</p>',2),(605,923,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les restaurants rapides proposent des plats équilibrés et variés, et ils respectent les normes d\'hygiène et les variétés de produits qui sont bons, et c\'est le client qui compose son menu, donc il en est responsable.</p>',1),(606,923,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La restauration rapide est néfaste à la santé, elle cause des problèmes irréversibles comme l\'obésité, etc.</p>',2),(607,926,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Vivre en colocation aide à créer des liens d\'amitié. Emménager avec un ami ou même avec une personne totalement nouvelle, avec qui on s\'entend à merveille, offre la possibilité de rentrer le soir en sachant qu\'on va rire, passer un bon moment et partager les repas : vous, votre télé et votre pizza. En plus, cela permet de partager les tâches ménagères et de profiter des talents de vos colocataires bricoleurs ou cuisiniers.</p>',1),(608,926,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Vivre en colocation est bien différent de vivre avec ses parents, frères et sœurs. Les rythmes de vie, les personnalités et les priorités peuvent être très variés. Partager une colocation avec la mauvaise personne peut rapidement transformer cette expérience en cauchemar. Le non-respect des tâches ménagères ou des espaces privés fait partie des principales sources de conflits. De plus, le bruit est un autre facteur de gêne. Par exemple, un colocataire passionné de jeux vidéo peut faire du bruit jusqu\'à 4 heures du matin.</p>',2),(609,929,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Daniel :<br>\r\n                        Je suis contre la consommation de viande en raison de préoccupations éthiques, environnementales et sanitaires. Éthiquement, je crois que tous les animaux ont droit à la vie et à la liberté, et que l\'élevage industriel implique souvent des traitements inhumains. Environnementalement, l\'élevage d\'animaux pour la viande est une source majeure de gaz à effet de serre et nécessite une grande quantité de terres et d\'eau, ce qui contribue au changement climatique et à la déforestation.</p>',1),(610,929,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Alain:<br>\r\n                        Je suis d\'accord avec la consommation de viande car elle est une source essentielle de protéines, de vitamines B et de minéraux comme le fer et le zinc. Bien que l\'on puisse obtenir ces nutriments à partir de sources végétales, ils sont souvent plus accessibles et plus facilement absorbés par le corps lorsqu\'ils proviennent de sources animales. De plus, la viande fait partie intégrante de nombreux régimes culturels et traditions culinaires, ce qui ajoute à sa valeur au-delà de la nutrition. Cependant, il est crucial de se procurer de la viande de manière responsable, en soutenant des pratiques d\'élevage éthiques et durables.</p>',2),(611,932,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le végétarisme présente plusieurs avantages importants. Tout d\'abord, il favorise la santé : manger des légumes et des fruits réduit les risques de maladies comme les problèmes cardiaques. De plus, le végétarisme aide à protéger l\'environnement en diminuant la pollution liée à la production de viande. Enfin, ce choix respecte la vie animale, une valeur partagée par de plus en plus d\'Européens.</p>',1),(612,932,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le végétarisme n\'est pas adapté à tous. Certaines personnes ont besoin de la viande pour obtenir des nutriments essentiels comme le fer et les protéines. En Europe, les habitudes alimentaires traditionnelles incluent souvent la viande, et il peut être difficile de changer ces pratiques. De plus, suivre un régime végétarien demande parfois plus de temps et de connaissances pour équilibrer les repas, ce qui n\'est pas toujours pratique.</p>',2),(613,935,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>L\'État devrait organiser de grands événements sportifs comme les Jeux Olympiques, la Coupe du Monde ou la Coupe d\'Afrique. Ces compétitions sont des occasions uniques de mettre en valeur notre culture et d\'attirer l\'attention du monde entier. Elles favorisent aussi l\'économie en créant des emplois et en modernisant les infrastructures, ce qui profite à long terme à toute la population.</p>',1),(614,935,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Il faut dire que ces grands événements sportifs représentent des dépenses considérables pour l\'État. Au lieu d\'investir dans des compétitions coûteuses, je pense que les fonds publics devraient être prioritairement alloués à des secteurs essentiels comme la santé et l\'éducation. De plus, de nombreux pays ayant accueilli ces événements se sont retrouvés endettés, sans bénéfices réels pour leurs citoyens.</p>',2),(615,938,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(616,938,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, …).</p>',2),(617,941,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>De plus en plus d\'écoles décident de mettre en place un menu sans viande dans les cantines, au moins deux fois par semaine. Certaines études ont montré que les enfants consomment trop de protéines animales. C\'est donc une question de santé : les écoles ont choisi de remplacer la viande par d\'autres produits (soja, céréales, légumes), moins gras et utiles à la croissance des enfants. Ces menus sans viandes à la cantine reviennent moins cher aux familles. Cette idée plaît beaucoup aux parents comme aux enfants.</p>',1),(618,941,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La décision de supprimer la viande dans les cantines ne plaît pas à tout le monde. En effet, c\'est un produit cher : la cantine est le seul endroit où les enfants de familles en difficulté peuvent manger. Les producteurs locaux de viande sont également mécontents: une partie de leur production est réservée aux cantines, il s\'agit donc d\'une perte financière. Enfin, beaucoup d\'enfants interrogés déclarent tout de même préférer les steaks de boeuf aux steaks de soja qui, selon eux, ont peu de goût.</p>',2),(619,944,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(620,944,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(621,947,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(622,947,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(623,950,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le port de l\'uniforme développe un sentiment d\'appartenance à son établissement, et à la communauté des élèves. Il nourrit chez le jeune le sens du collectif et engendre souvent la fierté d\'appartenir à son établissement. De plus, il réduit la discrimination basée sur le style ou sur la classe sociale de l\'élève. En effet, l\'uniforme permet aux parents d\'économiser beaucoup d\'argent, ce ne sont pas tous les parents griffés ou de marques populaires. La mise en place d\'un code vestimentaire réduit donc les différences entre les classes sociales.</p>',1),(624,950,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le port de l\'uniforme étouffe et écrase la personnalité des garçons. Ils ne peuvent pas s\'habiller comme ils le veulent, en aucune circonstance. De l\'autre côté de l\'échelle (chez les pros) il y a des gens qui préfèreraient, pour eux-mêmes et leurs enfants, avoir la possibilité de s\'exprimer à travers l\'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers I \'habillement, en décidant eux-mêmes ce qu\'ils porteront chaque jour. Ainsi, avec un uniforme, les jeunes qui aiment s\'exprimer à travers la mode, se démarquer de la foule grâce à un accessoire ou un vêtement particulier se retrouveront déçus et emprisonnés dans l\'uniforme.</p>',2),(625,953,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Dans l\'école où j\'enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentent rassurés quant à la sécurité des enfants et que cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(626,953,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Je suis opposé à l\'installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l\'administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l\'école par tous, plutôt que de recourir aux caméras.</p>',2),(627,956,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La location courte durée offre flexibilité et commodité pour les voyageurs. Elle permet de louer un logement pour une période de temps limitée, que ce soit pour des vacances ou un déplacement professionnel. Cela permet aux voyageurs de profiter d\'un hébergement confortable avec des équipements adaptés à leurs besoins, tout en évitant les engagements à long terme.</p>',1),(628,956,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La location courte durée peut parfois être coûteuse, en particulier dans les zones touristiques. De plus, la disponibilité peut être limitée, surtout pendant les périodes de forte demande. Il est donc important de planifier et de réserver à l\'avance pour obtenir les meilleurs résultats.</p>',2),(629,959,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d\'offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d\'information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(630,959,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d\'autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d\'un sport. Il est important de faire preuve de discernement et de réguler l\'exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d\'apprentissage et de divertissement.</p>',2),(631,960,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Vivre avec d\'autres personnes demande d\'avoir une bonne entente et de respecter certaines règles. Il n\'est pas toujours possible d\'écouter sa musique préférée à volume élevé, d\'inviter tous ses amis pour faire la fête ou de laisser de la vaisselle sale dans la cuisine. Chaque individu a des habitudes susceptibles d\'irriter les autres. C\'est pourquoi il est essentiel d\'établir des règles de vie en communauté et de les respecter mutuellement. Il est important de communiquer avec ses colocataires chaque fois qu\'un problème survient. L\'organisation et la discussion sont les clés d\'une colocation réussie ou non.</p>',1),(632,960,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Être adulte et vivre en colocation ? C\'est un choix qui permet d\'accéder facilement à un logement plus spacieux et économique. Il est vrai que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager la cuisine, le salon et la salle de bain. Toutefois, une colocation peut inclure une maison avec jardin ou un grand appartement en centre-ville ! De plus, en partageant le loyer et les charges avec vos colocataires, vous réduirez considérablement vos dépenses par rapport à un appartement individuel. Alors que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager les espaces communs, une colocation offre des opportunités de logements bien plus abordables.</p>',2),(633,963,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Vivre avec d\'autres personnes demande d\'avoir une bonne entente et de respecter certaines règles. Il n\'est pas toujours possible d\'écouter sa musique préférée à volume élevé, d\'inviter tous ses amis pour faire la fête ou de laisser de la vaisselle sale dans la cuisine. Chaque individu a des habitudes susceptibles d\'irriter les autres. C\'est pourquoi il est essentiel d\'établir des règles de vie en communauté et de les respecter mutuellement. Il est important de communiquer avec ses colocataires chaque fois qu\'un problème survient. L\'organisation et la discussion sont les clés d\'une colocation réussie ou non.</p>',1),(634,963,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Être adulte et vivre en colocation ? C\'est un choix qui permet d\'accéder facilement à un logement plus spacieux et économique. Il est vrai que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager la cuisine, le salon et la salle de bain. Toutefois, une colocation peut inclure une maison avec jardin ou un grand appartement en centre-ville ! De plus, en partageant le loyer et les charges avec vos colocataires, vous réduirez considérablement vos dépenses par rapport à un appartement individuel. Alors que vous n\'aurez qu\'une chambre pour vous et que vous devrez partager les espaces communs, une colocation offre des opportunités de logements bien plus abordables.</p>',2),(635,964,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(636,964,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(637,967,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(638,967,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(639,968,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec des taux de pollution alarmants constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation des voitures en zones urbaines. La capitale de Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure !</p>',1),(640,968,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins pollué, mais en contrepartie, il faut prévoir entre autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et Bus) et prévoir des autorisations de circulation pour certains corps de métier (comme la police, les urgentistes, les livreurs, etc.).</p>',2),(641,971,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Avec des taux de pollution alarmants constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation des voitures en zones urbaines. La capitale de Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure !</p>',1),(642,971,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins pollué, mais en contrepartie, il faut prévoir entre autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et Bus) et prévoir des autorisations de circulation pour certains corps de métier (comme la police, les urgentistes, les livreurs, etc.).</p>',2),(643,974,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>les enfants, jusqu\'à l\'âge de l\'adolescence, jouent d\'une manière régulière aux jeux vidéo et à force, ils peuvent développer des pensée négatives et des comportements agressifs. En effet, une étude récente, menée sur des enfants âgés de 9 à 18 ans jouant fréquemment aux jeux vidéo, a révélé que le fait de jouer à des jeux de violence augmente considérablement un comportement agressif. Et selon Diego Gentil, ce phénomène est inévitable quelque soit le degré de vigilance des parents!</p>',1),(644,974,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>On parle tout le temps des effets négatifs des jeux vidéo, mais ces derniers peuvent également avoir quelques avantages pour le fonctionnement du cerveau et pour la santé d\'une manière générale. si on prend, par exemple, leur rapport pour le cerveau, les jeux vidéo permettent d\'améliorer plusieurs fonctions cognitives telles que l\'amélioration de la concentration, de la création et de la capacité d\'analyse. Ceci peut paraitre évident, dans la mesure où lorsqu\'on y joue, on doit toujours trouver.</p>',2),(645,977,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les transports en commun gratuits, c\'est une très bonne idée. Cela permet de diminuer le nombre de voitures en ville et d\'éviter les bouchons. C\'est aussi une bonne mesure pour réduire la pollution et donc les risques de maladies respiratoires. Dans ma ville, il y a des transports en commun gratuits. On observe que les gens utilisent plus souvent les transports publics depuis que la gratuité est en place. Cette mesure a aussi profité aux commerçants : les gens reviennent faire leurs achats dans le centre-ville et vont moins dans les hypermarchés.</p>',1),(646,977,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>L\'idée n\'est pas bonne. D\'une part, cela coûterait cher aux villes. Or, il me semble que la ville de Toulouse a d\'autres problèmes à régler en priorité. Par exemple, il faudrait d\'abord réaménager les espaces verts, cela profiterait à tout le monde. D\'autre part, il vaudrait mieux réorganiser les transports publics au lieu de les rendre gratuits. Aujourd\'hui, les gens préfèrent prendre leur voiture parce que la ville manque de transports publics dans certains quartiers éloignés. Enfin, selon moi, il faut garder les transports publics payants. Les gens respecteront davantage les équipements s\'ils participent à leur financement en payant un titre de transport.</p>',2),(647,980,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(648,980,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, …)</p>',2),(649,983,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>les enfants, jusqu\'à l\'âge de l\'adolescence, jouent d\'une manière régulière aux jeux vidéo et à force, ils peuvent développer des pensée négatives et des comportements agressifs. En effet, une étude récente, menée sur des enfants âgés de 9 à 18 ans jouant fréquemment aux jeux vidéo, a révélé que le fait de jouer à des jeux de violence augmente considérablement un comportement agressif. Et selon Diego Gentil, ce phénomène est inévitable quelque soit le degré de vigilance des parents!</p>',1),(650,983,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>On parle tout le temps des effets négatifs des jeux vidéo, mais ces derniers peuvent également avoir quelques avantages pour le fonctionnement du cerveau et pour la santé d\'une manière générale. si on prend, par exemple, leur rapport pour le cerveau, les jeux vidéo permettent d\'améliorer plusieurs fonctions cognitives telles que l\'amélioration de la concentration, de la création et de la capacité d\'analyse. Ceci peut paraitre évident, dans la mesure où lorsqu\'on y joue, on doit toujours trouver.</p>',2),(651,986,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Opinion 1 : Karim,</p>\r\n                        <p>« Je suis en faveur des distributeurs de boissons dans les lycées. Premièrement, ils offrent une commodité supplémentaire pour les élèves, notamment pour ceux qui n\'ont pas le temps de passer à la cafétéria pendant les pauses. Deuxièmement, s\'ils sont bien gérés, ces distributeurs peuvent offrir une gamme de boissons saines, comme de l\'eau, du jus de fruits pur et des boissons aux fruits sans sucre ajouté. Ces distributeurs peuvent être une source de revenus supplémentaires pour l\'école, qui peut être réinvestie dans l\'amélioration des infrastructures ou des programmes scolaires. »</p>',1),(652,986,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Opinion 2 : elite tcf canada</p>\r\n                        <p>« Je suis contre l\'installation de distributeurs de boissons dans les lycées. Ma principale préoccupation est liée à la santé des élèves. Malheureusement, beaucoup de ces distributeurs sont remplis de boissons sucrées et de sodas qui contribuent à l\'obésité infantile et à d\'autres problèmes de santé comme le diabète. Même les jus de fruits, qui peuvent sembler sains, contiennent souvent beaucoup de sucre. Les écoles devraient être des lieux qui encouragent des habitudes alimentaires saines et je crains que la présence de ces distributeurs n\'encourage une consommation excessive de boissons sucrées. »</p>',2),(653,989,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivre les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(654,989,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(655,992,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Une étude menée par le Centre de recherche sur la parentalité de l\'Université de Toronto en juin dernier a révélé que la majorité des parents adoptent des approches plus bienveillantes envers leurs enfants qu\'auparavant. Cette étude a examiné un échantillon représentatif de mille familles dans différentes régions du pays et a montré que les parents encouragent une communication ouverte avec leurs enfants et adoptent des approches moins autoritaires.</p>',1),(656,992,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Un article d\'opinion paru dans un magazine populaire en mars 2023 présente des témoignages de parents qui ont recours à des méthodes de discipline plus strictes, telles que des privations de liberté, des punitions corporelles et des critiques constantes. Certains parents estiment que ces approches sont nécessaires pour aider leurs enfants à développer leur responsabilité et leur discipline dans un monde de plus en plus compétitif. Cependant, de nombreux experts en éducation considèrent ces méthodes comme inappropriées et préconisent des approches plus positives et coopératives pour guider les enfants vers un comportement approprié.</p>',2),(657,995,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(658,995,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués</p>',2),(659,998,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je vais bientôt avoir 22 ans et j\'habite toujours chez mes parents. Mon père et ma mère restent autoritaires avec moi, même si je suis majeure. Quand j\'étais mineure, je n\'avais pas le droit de dormir dehors, ni même de dépasser 21h lorsque je sortais avec des amies. Maintenant, peu de choses ont changé ; certes, j\'ai le droit de veiller plus tard la nuit, mais ma mère ne cesse de m\'appeler sur mon téléphone portable jusqu\'à ce que je sois de retour.</p>',1),(660,998,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les parents ont parfois peur d\'être trop sévères avec leurs enfants. Ils craignent, qu\'à cause d\'un excès d\'autorité, leurs enfants ne s\'épanouissent pas et manquent plus tard de personnalité. Même si les parents acceptent, par amour, tout ce dont leurs enfants demandent, cela pourrait avoir des effets négatifs lorsqu\'ils passent à l\'âge adulte. En effet, pour vivre en communauté, il y a certaines règles à respecter.</p>',2),(661,1001,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le supermarché est très pratique ; on y trouve une grande variété de produits, tous à portée de main. Vous pouvez garer votre voiture dans le parking et faire le tour des rayons pour acheter tout ce dont vous avez besoin : fruits, légumes, fromages, viandes, boissons… De plus, les supermarchés offrent plusieurs marques pour un même produit, tout en proposant régulièrement des promotions et des remises.</p>',1),(662,1001,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>ASSOCIATION POUR LA SAUVEGARDE DES PETITS COMMERCES</p>\r\n                        <p>Le défi « Février sans supermarché » a été créé pour limiter la superpuissance des supermarchés et, par conséquent, permettre aux petits commerces de survivre et de réaliser des chiffres d\'affaires plus conséquents. Ce défi consiste à boycotter les supermarchés pendant une durée d\'un mois, en faisant toutes ses courses dans les épiceries de quartier. Le client aura tout à gagner : il bénéficiera non seulement de produits frais de meilleure qualité, mais aura également l\'opportunité de papoter avec les voisins.</p>',2),(663,1004,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(664,1004,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(665,1007,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Je suis en faveur des distributeurs de boissons dans les lycées. Premièrement, ils offrent une commodité supplémentaire pour les élèves, notamment pour ceux qui n\'ont pas le temps de passer à la cafétéria pendant les pauses. Deuxièmement, s\'ils sont bien gérés, ces distributeurs peuvent offrir une gamme de boissons saines, comme de l\'eau, du jus de fruits pur et des boissons aux fruits sans sucre ajouté. Ces distributeurs peuvent être une source de revenus supplémentaire pour l\'école, qui peut être réinvestie dans l\'amélioration des infrastructures ou des programmes scolaires.</p>',1),(666,1007,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Je suis contre l\'installation de distributeurs de boissons dans les lycées. Ma principale préoccupation est liée à la santé des élèves. Malheureusement, beaucoup de ces distributeurs sont remplis de boissons sucrées et de sodas qui contribuent à l\'obésité infantile et à d\'autres problèmes de santé comme le diabète. Même les jus de fruits, qui peuvent sembler sains, contiennent souvent beaucoup de sucre. Les écoles devraient être des lieux qui encouragent des habitudes alimentaires saines et je crains que la présence de ces distributeurs n\'encourage une consommation excessive de boissons sucrées.</p>',2),(667,1010,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(668,1010,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(669,1013,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(670,1013,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(671,1016,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Marie, 58 ans :</p>\r\n                    <p>J\'ai pris l\'habitude, depuis des années maintenant, de donner un peu de mon temps et de mon argent afin d\'aider les personnes vivant dans la précarité extrême, surtout ceux qui vivent sans abri en période hivernale. Pour moi, c\'est un devoir d\'aider et de contribuer afin que ces personnes puissent vivre le plus normalement possible. En assistant des pauvres ou des associations, on se sent utile au sein d\'une société qui devient de plus en plus impitoyable.</p>',1),(672,1016,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Paul 63, ans :</p>\r\n                    <p>Pour aider les personnes vivant dans la précarité, on doit s\'investir davantage dans des associations caritatives. Personnellement, c\'est ce que je fais, je suis bénévole dans une association située dans mon quartier. Elle a pour principal but, aider les sans-abris à trouver un logement et un travail afin qu\'ils vivent le plus normalement possible. Cette action est plus bénéfique à long terme car elle permet de les rendre autonomes.</p>',2),(673,1019,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l\'avantage est avant tout économique. D\'une part, le livre numérique permet d\'économiser du papier, d\'autre part la version numérique d\'un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d\'augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(674,1019,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le livre numérique remplacera-t-il le livre papier ? « Non », répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu\'on aime ou de l\'offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l\'odeur du neuf ou de l\'ancien… Il transmet beaucoup d\'émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(675,1022,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Franck soutient l\'utilisation limitée du plastique, soulignant son importance dans de nombreux secteurs, notamment les secteurs médical et alimentaire. Pour lui, le plastique est vital pour la conservation des aliments et la stérilisation des équipements médicaux. Il prône une utilisation responsable et le recyclage, mais reconnaît que certains usages du plastique sont indispensables pour la société moderne.</p>',1),(676,1022,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Amicha s\'oppose fermement à l\'utilisation du plastique, mettant en avant son impact environnemental dévastateur. Elle soutient que les déchets plastiques polluent les océans et les écosystèmes, causant des dommages irréparables. Amicha milite pour des alternatives écologiques et durables, insistant sur l\'urgence de renoncer au plastique pour protéger l\'environnement et la santé publique.</p>',2),(677,1025,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d\'offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d\'information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(678,1025,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d\'autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d\'un sport. Il est important de faire preuve de discernement et de réguler l\'exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d\'apprentissage et de divertissement.</p>',2),(679,1028,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Grâce à la livraison en entreprise, les employés bénéficieront d\'un gain de temps notable. Il n\'est plus question d\'aller sortir loin du lieu de travail pour trouver de quoi manger. En complément, l\'argent et l\'énergie économisée permettent d\'être encore plus efficace au travail. Sans pour autant mettre fin à une session importante liée au travail, le repas sera déjà prêt et pourra attendre la fin d\'une conférence, d\'une réunion ou d\'un rendez-vous. Il s\'agit d\'une véritable solution dédiée aux entreprises ayant une activité intense et qui requiert la présence continue de leurs employés.</p>',1),(680,1028,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l\'attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(681,1031,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Apprendre une langue en ligne grace à Internet, c\'est possible et cela donne de bons résultats ! Contrairement aux cours classiques, on peut apprendre quand on veut : les cours sont disponibles tout le temps. Cela permet de mieux organiser sa journée. On n\'a pas non plus besoin de faire des kilomètres pour aller dans une école de langues. On peut apprendre de son salon, de son bureau ou même d\'un café près de chez soi ! Cela permet aussi de faire des économies.</p>',1),(682,1031,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cela semble facile d\'apprendre une langue en ligne mais ce n\'est pas possible pour tout le monde. En effet, il faut avoir une bonne connexion à Internet et un outil numérique adapté (ordinateur, smartphone, tablette) pour apprendre en ligne. De plus, il faut être très autonome pour être capable d\'apprendre seul : il est difficile de se mettre au travail chez soi et de rester motivé quand on n\'a pas l\'aide d\'un professeur et de collègues. Dans ces conditions, on peut se décourager et abandonner très vite.</p>',2),(683,1034,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Chaque année, des millions de tonnes de plastiques sont déversées dans les océans, où elles s\'accumulent et se fragmentent en petits morceaux. Ces déchets plastiques ont des effets désastreux sur la faune et la flore marines, qui les ingèrent. Les plastiques menacent ainsi la santé des écosystèmes marins, mais aussi la nôtre, car ils peuvent remonter dans la chaîne alimentaire. Il est urgent de réduire notre consommation de plastiques et de les éliminer à la source, avant qu\'ils n\'atteignent les océans.</p>',1),(684,1034,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le plastique est un matériau indispensable dans le domaine de la santé. Il permet de fabriquer des dispositifs médicaux, tels que des seringues, des cathéters, des prothèses, des implants, des pansements, etc. Ces dispositifs sont souvent jetables, résistants, et adaptés aux besoins des patients. Le plastique contribue ainsi à la prévention des infections, à la réduction des douleurs, à l\'amélioration de la qualité de vie, et à la sauvegarde de nombreuses vies. Il est donc un allié de la médecine, qui apporte des solutions innovantes et efficaces.</p>',2),(685,1037,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l\'avantage est avant tout économique. D\'une part, le livre numérique permet d\'économiser du papier, d\'autre part la version numérique d\'un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d\'augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(686,1037,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Le livre numérique remplacera-t-il le livre papier ? « Non », répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu\'on aime ou de l\'offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l\'odeur du neuf ou de l\'ancien… Il transmet beaucoup d\'émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(687,1040,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Aïcha, jeune célibataire française de 28 ans, refuse de prendre ses repas seule chez elle. « Me retrouver avec un plateau repas devant la télé, non merci ! Vivre à Lyon me donne la possibilité de dîner à l\'extérieur, où je veux et à n\'importe quelle heure. Pourquoi m\'en priver ? Je trouve aussi génial de pouvoir partager des moments de convivialité avec tous mes amis, ce qui est impossible dans mon petit appartement. Et puis, c\'est vrai, peu de gens de ma génération ont la patience et le talent de préparer des petits plats maison. »</p>',1),(688,1040,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Laura, mère de famille de 45 ans, déclare : « Dîner au restaurant est un luxe que je peux rarement m\'offrir avec mon salaire de vendeuse. Bien sûr, j\'aimerais parfois éviter de faire la cuisine et pouvoir sortir au restaurant, mais pour une famille de cinq personnes, la dépense est énorme ! Et puis je trouve que la qualité des plats servis dans les restaurants est très moyenne. Le rapport qualité-prix n\'est pas toujours au rendez-vous. Au moins, en mangeant à la maison, je sais ce qu\'il y a dans mon assiette. »</p>',2),(689,1043,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je suis en faveur des distributeurs de boissons dans les lycées. Premièrement, ils offrent une commodité supplémentaire pour les élèves, notamment pour ceux qui n\'ont pas le temps de passer à la cafétéria pendant les pauses. Deuxièmement, s\'ils sont bien gérés, ces distributeurs peuvent offrir une gamme de boissons saines, comme de l\'eau, du jus de fruits pur et des boissons aux fruits sans sucre ajouté. Ces distributeurs peuvent être une source de revenus supplémentaires pour l\'école, qui peut être réinvestie dans l\'amélioration des infrastructures ou des programmes scolaires.</p>',1),(690,1043,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Je suis contre l\'installation de distributeurs de boissons dans les lycées. Ma principale préoccupation est liée à la santé des élèves. Malheureusement, beaucoup de ces distributeurs sont remplis de boissons sucrées et de sodas qui contribuent à l\'obésité infantile et à d\'autres problèmes de santé comme le diabète. Même les jus de fruits, qui peuvent sembler sains, contiennent souvent beaucoup de sucre. Les écoles devraient être des lieux qui encouragent des habitudes alimentaires saines et je crains que la présence de ces distributeurs n\'encourage une consommation excessive de boissons sucrées.</p>',2),(691,1046,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(692,1046,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(693,1049,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(694,1049,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(695,1052,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Christine, 56 ans :</p>\r\n                        <p>Tous les ans, en hiver, je donne un peu de mon temps et de mon argent pour aider les personnes qui vivent dans la rue et ont froid. Pour moi, c’est important de se soucier de ceux qui sont dans le besoin. Je trouve très important de donner quelques dollars à ces personnes ou aux associations qui peuvent les aider. Et puis, cette action me donne l’impression d’être utile, au moins une fois dans l’année ! C’est un geste de solidarité qui est à la portée de tout le monde.</p>',1),(696,1052,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Pierre, 65 ans :</p>\r\n                        <p>Plutôt que de donner de l’argent à des personnes pauvres, il vaudrait mieux revoir notre mode de vie. C’est pourquoi je préfère m’engager au quotidien dans une association de mon quartier, où je suis bénévole. Les sans domicile fixe ont besoin d’un logement et d’un travail et pas seulement d’argent. Il faut les aider à devenir autonomes. C’est le but d\'organismes qui aident ceux qui sont dans la rue à trouver un emploi. Donner de l’argent est un acte inutile qui sert seulement à apaiser notre conscience.</p>',2),(697,1055,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Avec des taux de pollution alarmantes constatés dans plusieurs endroits dans le monde, plusieurs villes ont réussi leur pari d\'interdire la circulation de voitures en zones urbaines. La capitale de la Norvège, Oslo, a récemment opté pour cette solution et s\'en félicite estimant que c\'est une décision bénéfique pour tout le monde. Après un certain temps, les accidents diminueront, la dépendance au pétrole baissera et la qualité d\'air sera meilleure.</p>',1),(698,1055,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Beaucoup de villes se lancent dans des projets d\'interdiction de voitures en zone urbaine sans mettre en place les outils et les infrastructures nécessaires pour réussir cette transition. Certes, en diminuant les voitures, on aura moins d\'embouteillages, de stress et surtout un air beaucoup moins pollué, mais en contrepartie, il faut prévoir entre- autres de gigantesques parkings pour garer les voitures, opter davantage pour le transport en commun (métros et bus) et prévoir des autorisations de circulation pour certains corps de métiers (comme la police, les urgentistes, les livreurs, …).</p>',2),(699,1058,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>De plus en plus d\'écoles décident de mettre en place un menu sans viande dans les cantines, au moins deux fois par semaine. Certaines études ont montré que les enfants consomment trop de protéines animales. C\'est donc une question de santé : les écoles ont choisi de remplacer la viande par d\'autres produits (soja, céréales, légumes), moins gras et utiles à la croissance des enfants. Ces menus sans viandes à la cantine reviennent moins cher aux familles. Cette idée plaît beaucoup aux parents comme aux enfants.</p>',1),(700,1058,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La décision de supprimer la viande dans les cantines ne plaît pas à tout le monde. En effet, c\'est un produit cher : la cantine est le seul endroit où les enfants de familles en difficulté peuvent manger. Les producteurs locaux de viande sont également mécontents: une partie de leur production est réservée aux cantines, il s\'agit donc d\'une perte financière. Enfin, beaucoup d\'enfants interrogés déclarent tout de même préférer les steaks de boeuf aux steaks de soja qui, selon eux, ont peu de goût.</p>',2),(701,1061,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Je fais souvent mes voyages avec des compagnies aériennes à bas prix. Les compagnies Low-cost mettent à disposition des prix inférieurs à ceux proposés par les compagnies aériennes régulières. Cela me coûte des fois moins chère que de voyager en voiture ou en train. Avec ces tarifs-là, vous en doutez qu\'il y a un hic, en effet, vous n\'aurez le droit à aucun service à bord (ni aliments, ni boissons). Je dirais donc, que le low-cost n\'est surtout pas fait pour les vols long courrier.</p>',1),(702,1061,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Récemment, j\'ai pris la décision de ne plus voyager avec les compagnies aériennes à bas prix. En effet, j\'ai longuement réfléchi afin de prendre ma décision, mais ce choix était évident : des sièges inconfortables, des conditions de travail pénibles et surtout des avions vétustes qui remettent en cause la sécurité ! Dès lors, pour certains voyages, je vais opter pour la voiture ou même le train, ce dernier permet même de découvrir de jolis paysages. Quant aux longs trajets, vaut mieux prendre un vol en compagnie régulière.</p>',2),(703,1064,1,'Document 1 :','<p>\"Je suis de ceux qui n\'arrivent pas à comprendre comment l\'on peut prendre du plaisir à tuer des animaux. Je suis de ceux qui n\'arrivent pas à comprendre comment on peut prétendre aimer la nature alors qu\'on la détruit\" Gala 29 ans</p>',1),(704,1064,2,'Document 2 :','<p>\"Les gens chassent pour différentes raisons : la subsistance, le commerce, la conversation et l\'aménagement de la faune, la protection de la propriété, l\'exercice, le loisir et le prestige.\" David, Journaliste de la FRM</p>',2),(705,1067,1,'Document 1 :','<p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(706,1067,2,'Document 2 :','<p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(707,1070,1,'Document 1 :','<p>La livraison de repas permet de gagner du temps. Par exemple, quand on travaille, on peut se faire livrer un repas au bureau sans se déplacer. On perd moins de temps pendant la pause déjeuner, on rentre donc plus tôt chez soi. Généralement, cela offre plus de choix : si un de nos collègues veut commander une pizza mais que nous souhaitons manger des sushis, plus de disputes, il suffit de commander des plats dans différents restaurants. L\'autre avantage de ce nouveau mode de consommation est qu\'il est disponible à toute heure. En effet, on trouve toujours des restaurants qui restent ouverts 24 heures sur 24. Céline, 25 ans</p>',1),(708,1070,2,'Document 2 :','<p>Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l\'attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(709,1073,1,'Document 1 :','<p>De nos jours, il y a de plus en plus de caméras de surveillance dans les villes. La vidéosurveillance est appréciée par les Français car cela leur donne un sentiment de sécurité. D\'après un sondage, 75% d\'entre eux sont pour le développement de la vidéosurveillance. Ils seraient d\'accord pour être filmés, mais seulement dans l\'espace public: la rue, les magasins ou encore les transports. Cependant, ils refusent d\'être surveillés par leur employeur. En France, peu de caméras de vidéosurveillance sont installées sur le lieu de travail.</p>',1),(710,1073,2,'Document 2 :','<p>Certaines enquêtes montrent que la vidéo surveillance coûte cher et que ses résultats sont insuffisants. D\'une part, la présence des caméras est facile à remarquer. Par conséquent, la vidéo surveillance est inutile pour éviter les vols, la consommation de drogue et la violence dans les villes. D\'autre part, l\'utilisation de vidéo surveillance demande beaucoup de personnel. Une étude allemande montre que sept personnes par caméra sont nécessaires pour analyser les informations.</p>',2),(711,1076,1,'Document 1 :','<p>Les jeux vidéo ont la réputation d\'être néfastes; cependant, plusieurs études montrent qu\'en y jouant, un adulte peut développer des capacités cognitives; ils permettent par exemple d\'améliorer l\'aptitude à réagir. Cela peut être considéré comme un point positif surtout si on sait que 88,4% des joueurs sont des adultes. Cela dit, il faut rester vigilant car de nombreux jeux favorisent plutôt la violence et l\'addiction et ne développent par conséquent aucune zone du cerveau.</p>',1),(712,1076,2,'Document 2 :','<p>Vu les chiffres d\'affaires de plus en plus importants qu\'ils réalisent, les jeux vidéo font régulièrement l\'objet de plusieurs études. Parmi ces études, une qui a duré trois ans et qui s\'est intéressée à des enfants âgés de 8 à 17 ans. Son résultat n\'est sans doute pas une grande surprise; les enfants les plus addicts aux jeux développent des comportement violents, nerveux et sont souvent stressés. Dans certains cas, cela peut même se répercuter sur les résultats scolaires. Il est donc primordial que les parents interviennent afin d\'imposer des règles et limiter les temps de jeu.</p>',2),(713,1079,1,'Document 1 :','<p>Nous avons installé, dans votre entreprise, des bureaux réglables qui montent et descendent, ceci pour permettre aux employés de choisir la position qui leur convient le mieux pour travailler. Les employés sont satisfaits et disent qu\'ils sont plus productifs et plus efficaces lors des négociations au téléphone par exemple. Même le climat social est plus convivial et la communication verbale entre collègues s\'est renforcée. « Lorie, responsable ».</p>',1),(714,1079,2,'Document 2 :','<p>De nos jours, les entreprises veulent toujours plus de productivité et d\'efficacité, et les employés passent plus de temps sur les lieux de travail. Les entreprises cherchent toujours des moyens ou astuces pour convaincre leurs employés de travailler plus et qu\'elles pensent à leur santé. Moi, ce qui m\'importe c\'est de faire mon job sur mon temps de travail réel sans être obligé de faire des rallonges en heures supplémentaires. « Florian, ingénieur ».</p>',2),(715,1082,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Certains postes sont majoritairement occupés par des hommes. Au Québec, l\'égalité entre les femmes et les hommes est respectée, les femmes peuvent les métiers réservés aux hommes tel que les postes de direction.</p>',1),(716,1082,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Malgré les efforts pour imposer la parité à tous les postes dans les entreprises et les collectivités, il y a, dans les faits, des métiers où les femmes sont largement majoritaires tels que : les sage-femmes. De plus, les femmes ne doivent pas faire les métiers d\'homme, car ils doivent prendre soin de ses enfants.</p>',2),(717,1085,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les transports en commun gratuits, c\'est une très bonne idée. Cela permet de diminuer le nombre de voitures en ville et d\'éviter les bouchons. C\'est aussi une bonne mesure pour réduire la pollution et donc les risques de maladies respiratoires. Dans ma ville, il y a des transports en commun gratuits. On observe que les gens utilisent plus souvent les transports publics depuis que la gratuité est en place. Cette mesure a aussi profité aux commerçants : les gens reviennent faire leurs achats dans le centre-ville et vont moins dans les hypermarchés.</p>',1),(718,1085,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>L\'idée n\'est pas bonne. D\'une part, cela coûterait cher aux villes. Or, il me semble que la ville de Toulouse a d\'autres problèmes à régler en priorité. Par exemple, il faudrait d\'abord réaménager les espaces verts, cela profiterait à tout le monde. D\'autre part, il vaudrait mieux réorganiser les transports publics au lieu de les rendre gratuits. Aujourd\'hui, les gens préfèrent prendre leur voiture parce que la ville manque de transports publics dans certains quartiers éloignés. Enfin, selon moi, il faut garder les transports publics payants. Les gens respecteront davantage les équipements s\'ils participent à leur financement en payant un titre de transport.</p>',2),(719,1088,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivre les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(720,1088,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(721,1091,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>À la rentrée, le nombre d\'élèves inscrits dans des écoles privées a augmenté en France. Le succès des établissements privés n\'est pas directement lié aux bons résultats scolaires de leurs élèves. C\'est la réputation de ces lieux qui explique un tel enthousiasme. Aux yeux de nombreux parents, les élèves y sont mieux encadrés, mieux surveillés et les professeurs sont plus présents. Les parents sont aussi rassurés parce que les classes sont homogènes : elles accueillent généralement des élèves de milieux sociaux favorisés. En effet, les études dans ces établissements sont payantes, ce qui n\'est pas le cas dans les écoles publiques.</p>',1),(722,1091,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Dans les collèges privés, il y a peu d\'élèves de milieux sociaux défavorisés. Comme les études dans ces établissements sont payantes, certaines catégories de population en sont exclues. Ce système qui oppose écoles publiques et écoles privées ne facilite pas la mixité sociale. Ainsi, les élèves du privé ont rarement l\'occasion de rencontrer d\'autres jeunes issus de milieux sociaux moins favorisés qu\'eux et inversement. Ce modèle scolaire reproduit les inégalités sociales et renforce le sentiment d\'exclusion de certains jeunes.</p>',2),(723,1094,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(724,1094,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(725,1097,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Jean : Je suis fermement convaincu que l\'intégration des nouvelles technologies dans les écoles est cruciale pour préparer les élèves à un avenir numérique. Je pense que l\'usage des tablettes et des ordinateurs stimule non seulement l\'engagement des élèves mais enrichit également leur expérience éducative en leur offrant un accès facile à une variété de ressources, encourageant ainsi leur créativité et autonomie.</p>',1),(726,1097,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Sara : Je suis sceptique quant à l\'usage intensif des technologies dans l\'enseignement. Je crois que cela peut réduire les interactions humaines essentielles et favoriser une dépendance préoccupante aux écrans. À mon avis, les méthodes d\'enseignement traditionnelles et le contact direct entre enseignants et élèves restent indispensables pour un développement équilibré et complet des compétences des jeunes.</p>',2),(727,1100,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>De nos jours, il y a de plus en plus de caméras de surveillance dans les villes. La vidéosurveillance est appréciée par les Français car cela leur donne un sentiment de sécurité. D\'après un sondage, 75% d\'entre eux sont pour le développement de la vidéosurveillance. Ils seraient d\'accord pour être filmés, mais seulement dans l\'espace public: la rue, les magasins ou encore les transports. Cependant, ils refusent d\'être surveillés par leur employeur. En France, peu de caméras de vidéosurveillance sont installées sur le lieu de travail.</p>',1),(728,1100,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Certaines enquêtes montrent que la vidéo surveillance coûte cher et que ses résultats sont insuffisants. D\'une part, la présence des caméras est facile à remarquer. Par conséquent, la vidéo surveillance est inutile pour éviter les vols, la consommation de drogue et la violence dans les villes. D\'autre part, l\'utilisation de vidéo surveillance demande beaucoup de personnel. Une étude allemande montre que sept personnes par caméra sont nécessaires pour analyser les informations.</p>',2),(729,1103,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(730,1103,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(731,1106,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer plus de temps à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress, améliorant ainsi leur productivité globale.</p>',1),(732,1106,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La réduction du temps de travail peut bénéficier aux entreprises en diminuant l\'absentéisme et en améliorant la rétention des employés. Avec des horaires plus flexibles, les employés sont souvent plus motivés et engagés. Cependant, cela nécessite une bonne organisation et une adaptation des processus pour maintenir l\'efficacité et répondre aux besoins de l\'entreprise.</p>',2),(733,1109,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer more time à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress, améliorant ainsi leur productivité globale.</p>',1),(734,1109,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>La réduction du temps de travail peut bénéficier aux entreprises en diminuant l\'absentéisme et en améliorant la rétention des employés. Avec des horaires plus flexibles, les employés sont souvent plus motivés et engagés. Cependant, cela nécessite une bonne organisation et une adaptation des processus pour maintenir l\'efficacité et répondre aux besoins de l\'entreprise.</p>',2),(735,1112,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>le texte affirme que les zoos ont beaucoup d\'avantages, même pour les animaux en la voie de disparition, les animaux sont bien soignées dans les zoos. Les études montrent que le nombre de reproduction a augmenté grâce aux zoos et ils peuvent sauver la vie des animaux.</p>',1),(736,1112,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>le texte a montré qu\'il ne faut pas mettre les animaux sauvages dans les zoos parce que ce n\'est pas leur environnement. C\'est un prison pour eux. On trouve des ours polaires dans un zoo dont la température est de 15 degrés. Les animaux ont besoin de la nature et de la liberté.</p>',2),(737,1115,1,'Document 1 :','<p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(738,1115,2,'Document 2 :','<p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(739,1118,1,'Document 1 :','<p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(740,1118,2,'Document 2 :','<p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(741,1121,1,'Document 1 :','<p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(742,1121,2,'Document 2 :','<p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(743,1124,1,'Document 1 :','<p>Les amitiés entre collègues au travail peuvent être extrêmement bénéfiques. Elles favorisent un climat de travail agréable et une ambiance positive au sein de l\'équipe. Avoir des amis parmi ses collègues permet de renforcer les liens professionnels et de créer un sentiment de camaraderie. Cela peut contribuer à une meilleure communication, une collaboration plus étroite et une résolution plus efficace des problèmes. De plus, partager des moments de convivialité en dehors du travail, comme des déjeuners ou des activités après le bureau peut renforcer les liens et créer une dynamique de groupe solide.</p>',1),(744,1124,2,'Document 2 :','<p>Il est important de trouver un équilibre entre amitié et professionnalisme au travail. Les amitiés excessivement proches peuvent parfois créer des tensions ou des conflits lorsque des décisions professionnelles doivent être prises. De plus, les amitiés exclusives entre certains collègues peuvent exclure les autres membres de l\'équipe, ce qui peut nuire à la cohésion et à la collaboration. Il est essentiel de maintenir des limites claires et de veiller à ce que les amitiés ne compromettent pas le professionnalisme, la hiérarchie ou la productivité au sein de l\'organisation.</p>',2),(745,1127,1,'Document 1 :','<p>Aujourd\'hui, certains candidats mettent une photo sur leur CV, d\'autres non. Il faudrait interdire les photos sur les CV pour éviter les discriminations et les injustices. Selon une étude menée par des spécialistes de l\'emploi, cette pratique est inutile. L\'étude révèle que les employeurs prêtent plus attention à l\'expérience professionnelle (32%) et aux diplômes (15%) qu\'à l\'apparence physique. Seulement 2% des employeurs commencent la lecture d\'un CV par la photo. C\'est une statistique surprenante, surtout quand on connaît l\'importance que certaines personnes accordent à leur apparence physique.</p>',1),(746,1127,2,'Document 2 :','<p>La question de la photo sur le CV divise les employeurs. Pour certains, la photo permet de mieux se représenter la personne avant de la rencontrer. De plus, une photo peut aider à se souvenir d\'un candidat lorsqu\'un grand nombre de CV sont reçus. Pour d\'autres, cela dépend du poste : pour des métiers d\'accueil, par exemple, il peut être pertinent d\'inclure une photo. Cependant, elle doit toujours être professionnelle pour donner une impression positive.</p>',2),(747,1130,1,'Document 1 :','<p>Vivre avec d\'autres personnes demande d\'avoir une bonne entente et de respecter certaines règles. Il n\'est pas toujours possible d\'écouter sa musique préférée à volume élevé, d\'inviter tous ses amis pour faire la fête ou de laisser de la vaisselle sale dans la cuisine. Chaque individu a des habitudes susceptibles d\'irriter les autres. C\'est pourquoi il est essentiel d\'établir des règles de vie en communauté et de les respecter mutuellement. Il est important de communiquer avec ses colocataires chaque fois qu\'un problème survient. L\'organisation et la discussion sont les clés d\'une colocation réussie.</p>',1),(748,1130,2,'Document 2 :','<p>Être adulte et vivre en colocation ? C\'est un choix qui permet d\'accéder à un logement plus spacieux et économique. Il est vrai que vous n\'aurez qu\'une chambre pour vous, et que vous devrez partager la cuisine, le salon et la salle de bain. Toutefois, une colocation peut inclure une maison avec jardin ou un grand appartement en centre-ville ! En partageant le loyer et les charges avec vos colocataires, vous réduirez considérablement vos dépenses par rapport à un appartement individuel. Ainsi, même si vous n\'aurez qu\'une chambre à vous et devrez partager les espaces communs, la colocation offre des opportunités de logements bien plus abordables.</p>',2),(749,1133,1,'Document 1 :','<p>Tous les ans, en hiver, je donne un peu de mon temps et de mon argent pour aider les personnes qui vivent dans la rue et ont froid. Pour moi, c\'est important de se soucier de ceux qui sont dans le besoin. Je trouve très important de donner quelques dollars à ces personnes ou aux associations qui peuvent les aider. Et puis, cette action me donne l\'impression d\'être utile, au moins une fois dans l\'année ! C\'est un geste de solidarité qui est à la portée de tout le monde.</p>',1),(750,1133,2,'Document 2 :','<p>Pierre, 65 ans : Plutôt que de donner de l\'argent à des personnes pauvres, il vaudrait mieux revoir notre mode de vie. C\'est pourquoi je préfère m\'engager au quotidien dans une association de mon quartier, où je suis bénévole. Les sans domicile fixe ont besoin d\'un logement et d\'un travail et pas seulement d\'argent. Il faut les aider à devenir autonomes. C\'est le but d\'oganismes qui aident ceux qui sont dans la rue à trouver un emploi. Donner de l\'argent est un acte inutile qui sert seulement à apaiser notre conscience.</p>',2),(751,1136,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>les enfants, jusqu\'à l\'âge de l\'adolescence, jouent d\'une manière régulière aux jeux vidéo et à force, ils peuvent développer des pensée négatives et des comportements agressifs. En effet, une étude récente, menée sur des enfants âgés de 9 à 18 ans jouant fréquemment aux jeux vidéo, a révélé que le fait de jouer à des jeux de violence augmente considérablement un comportement agressif. Et selon Diego Gentil, ce phénomène est inévitable quelque soit le degré de vigilance des parents!</p>',1),(752,1136,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>On parle tout le temps des effets négatifs des jeux vidéo, mais ces derniers peuvent également avoir quelques avantages pour le fonctionnement du cerveau et pour la santé d\'une manière générale. si on prend, par exemple, leur rapport pour le cerveau, les jeux vidéo permettent d\'améliorer plusieurs fonctions cognitives telles que l\'amélioration de la concentration, de la création et de la capacité d\'analyse. Ceci peut paraitre évident, dans la mesure où lorsqu\'on y joue, on doit toujours trouver.</p>',2),(753,1139,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>le texte a montré qu\'il ne faut pas mettre les animaux sauvages dans les zoos parce que ce n\'est pas leur environnement. C\'est un prison pour eux. On trouve des ours polaires dans un zoo dont la température est de 15 degrés. Les animaux ont besoin de la nature et de la liberté.</p>',1),(754,1139,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>le texte affirme que les zoos ont beaucoup d\'avantages, même pour les animaux en la voie de disparition, les animaux sont bien soignées dans les zoos. Les études montrent que le nombre de reproduction a augmenté grâce aux zoos et ils peuvent sauver la vie des animaux.</p>',2),(755,1142,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(756,1142,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(757,1145,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                        <p>Les jeux vidéo, sur console ou sur ordinateur, chez soi ou en salle, seul, avec des amis ou en ligne avec des inconnus, peuvent provoquer une dépendance chez certaines personnes. On parle d\'addiction quand le jeu vidéo devient le principal (ou l\'unique) centre d\'intérêt, à la place d\'autres activités (relationnelle, professionnelle, scolaire, loisirs, sport…). Cette dépendance est particulièrement préoccupante lors de l\'adolescence, période importante où les jeux vidéo peuvent avoir un impact négatif sur les résultats scolaires.</p>',1),(758,1145,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                        <p>Les jeux vidéo, sur console ou sur ordinateur, chez soi ou en salle, seul, avec des amis ou en ligne avec des inconnus, peuvent provoquer une dépendance chez certaines personnes. On parle d\'addiction quand le jeu vidéo devient le principal (ou l\'unique) centre d\'intérêt, à la place d\'autres activités (relationnelle, professionnelle, scolaire, loisirs, sport…). Cette dépendance est particulièrement préoccupante lors de l\'adolescence, période importante où les jeux vidéo peuvent avoir un impact négatif sur les résultats scolaires.</p>',2),(759,1148,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(760,1148,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(761,1151,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Offrir un animal de compagnie à un enfant présente de nombreux avantages, comme le soulignent beaucoup de psychologues. Pour des enfants qui n\'ont pas des frères et/ou des sœurs, l\'animal est un compagnon qui leur évitera la solitude. Grâce à lui, un enfant prendra confiance en lui et il apprendra vite qu\'un animal est un être vivant qui a besoin d\'attention et de respect. En sa présence, l\'enfant se sentira en sécurité et pourra agir de manière autonome, sans l\'aide de ses parents.</p>',1),(762,1151,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Beaucoup d\'enfants demandent, un jour ou l\'autre, un animal à leurs parents, le plus souvent un chien ou un chat. Mais même si vous avez envie de faire plaisir à votre enfant, il vaut mieux réfléchir sérieusement avant d\'acheter un animal domestique. L\'animal devient un nouveau membre de la famille et représente un engagement sur de nombreuses années. Or, avoir un animal coûte souvent très cher, et c\'est une grande responsabilité. On ne peut pas le traiter comme un jouet que l\'on met à la poubelle quand l\'enfant s\'en désintéresse.</p>',2),(763,1154,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Jean : Je suis fermement convaincu que l\'intégration des nouvelles technologies dans les écoles est cruciale pour préparer les élèves à un avenir numérique. Je pense que l\'usage des tablettes et des ordinateurs stimule non seulement l\'engagement des élèves mais enrichit également leur expérience éducative en leur offrant un accès facile à une variété de ressources, encourageant ainsi leur créativité et autonomie.</p>',1),(764,1154,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Sara : Je suis sceptique quant à l\'usage intensif des technologies dans l\'enseignement. Je crois que cela peut réduire les interactions humaines essentielles et favoriser une dépendance préoccupante aux écrans. À mon avis, les méthodes d\'enseignement traditionnelles et le contact direct entre enseignants et élèves restent indispensables pour un développement équilibré et complet des compétences des jeunes.</p>',2),(765,1157,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Selon des associations des parents d\'élèves, les devoirs à la maison sont utiles, car ils permettent aux élèves d\'apprendre à organiser leur temps de manière autonome. Pour les parents, les devoirs sont lien quotidien avec l\'école. Même s\'il est parfois difficile de suivre les devoirs après une journée de travail fatigant, ils apprécient ce moment partagé avec leurs enfants parce que ceux-ci sont contents que leurs parents s\'intéressent à eux. C\'est valorisant !</p>',1),(766,1157,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Nous protestons depuis longtemps contre les devoirs à la maison pour plusieurs raisons. Personne ne jamais prouve leur utilité pour améliorer les résultats des élèves. Beaucoup de parents ont peu de temps pour encadrer les devoirs de leurs enfants et certains parents ne savent pas le faire. Quant aux élèves, ceux qui ont réussi les exercices en classe perdent leurs temps à faire à la maison. Ceux qui ne sont pas aidés à la maison ne réussissent toujours pas, ils sont défavorisés. C\'est pourquoi nous pensons qu\'il faut supprimer les devoirs à la maison.</p>',2),(767,1160,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>À la rentrée, le nombre d\'élèves inscrits dans des écoles privées a augmenté en France. Le succès des établissements privés n\'est pas directement lié aux bons résultats scolaires de leurs élèves. C\'est la réputation de ces lieux qui explique un tel enthousiasme. Aux yeux de nombreux parents, les élèves y sont mieux encadrés, mieux surveillés et les professeurs sont plus présents. Les parents sont aussi rassurés parce que les classes sont homogènes : elles accueillent généralement des élèves de milieux sociaux favorisés. En effet, les études dans ces établissements sont payantes, ce qui n\'est pas le cas dans les écoles publiques.</p>',1),(768,1160,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Dans les collèges privés, il y a peu d\'élèves de milieux sociaux défavorisés. Comme les études dans ces établissements sont payantes, certaines catégories de population en sont exclues. Ce système qui oppose écoles publiques et écoles privées ne facilite pas la mixité sociale. Ainsi, les élèves du privé ont rarement l\'occasion de rencontrer d\'autres jeunes issus de milieux sociaux moins favorisés qu\'eux et inversement. Ce modèle scolaire reproduit les inégalités sociales et renforce le sentiment d\'exclusion de certains jeunes.</p>',2),(769,1163,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Fabriquer vos propres produits biologiques à la maison offre un contrôle total sur les ingrédients, garantissant des options plus saines et personnalisées. Cela contribue également à réduire les déchets plastiques grâce à des emballages réutilisables. De plus, vous économiserez de l\'argent à long terme et développerez des compétences créatives, favorisant ainsi un mode de vie plus durable.</p>',1),(770,1163,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cependant, la fabrication de produits biologiques à domicile comporte des risques. Les erreurs de formulation peuvent entraîner des produits inefficaces ou irritants. De plus, le temps et les efforts nécessaires pour trouver et préparer les ingrédients peuvent être contraignants. Il y a également un manque de garantie de sécurité et de stabilité des produits faits maison, avec un risque accru de contamination bactérienne si les produits ne sont pas correctement conservés. Enfin, le coût initial élevé pour l\'achat d\'ingrédients de qualité peut être dissuasif pour certains.</p>',2),(771,1166,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les vêtements de marques sont très importants pour les enfants et les adolescents. C\'est un moyen de s\'exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leurs personnalités. Les enfants aiment également porter des vêtements de marques avec des images des dessins animés qu\'ils regardent ou des logos qu\'ils apprécient.</p>',1),(772,1166,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits.</p>\r\n                    <p>Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l\'extérieur avec les copains, en s\'amusant dans l\'herbe ou à l\'air de jeux. Les habits sont très vite sales ou troués.</p>',2),(773,1169,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Dans l\'école où j\'enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentent rassurés quant à la sécurité des enfants et que cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(774,1169,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Je suis opposé à l\'installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l\'administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l\'école par tous, plutôt que de recourir aux caméras.</p>',2),(775,1171,1,NULL,'<p>&gt; Je suis étudiante et je vais partir étudier un an à l\'étranger. Mais, j\'ai un peu peur. Qui a déjà fait cela ?<br>&gt; Justine.</p>',1),(776,1172,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Maman d\'une petite fille, Anna témoigne :</p>\r\n                    <p>&gt; « Lorsque je travaillais 5 jours par semaine, j\'utilisais mon temps de repos pour faire des tâches ménagères : rangement, nettoyage, lessives, etc. Je devais aussi faire les courses le samedi, au moment où il y a le plus de monde ! Maintenant, j\'ai plus de temps libre. Je profite de ma fille et je peux faire des activités qui me plaisent. Je ne voudrais pas travailler de nouveau 5 jours par semaine. »</p>',1),(777,1172,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Jack, 45 ans, donne son avis :<br>\r\n                    « La réduction du temps de travail hebdomadaire n\'est pas une bonne idée. La quantité de travail ne diminue pas, et le nombre de réunions non plus. On doit donc tout faire plus vite ! Selon moi, cette organisation du temps de travail est beaucoup plus fatigante. La réduction du temps de travail peut avoir des conséquences très négatives. »</p>',2),(778,1175,1,NULL,'<p><strong>Document 1 :</strong><br>\r\n                    Yannick :<br>\r\n                    D\'après moi, l\'État devrait organiser de grands événements sportifs comme les Jeux Olympiques, la Coupe du Monde ou la Coupe d\'Afrique. Ces compétitions sont des occasions uniques de mettre en valeur notre culture et d\'attirer l\'attention du monde entier. Elles favorisent aussi l\'économie en créant des emplois et en modernisant les infrastructures, ce qui profite à long terme à toute la population.</p>',1),(779,1175,2,NULL,'<p><strong>Document 2 :</strong><br>\r\n                    Karim :<br>\r\n                    Il faut dire que ces grands événements sportifs représentent des dépenses considérables pour l\'État. Au lieu d\'investir dans des compétitions coûteuses, je pense que les fonds publics devraient être prioritairement alloués à des secteurs essentiels comme la santé et l\'éducation. De plus, de nombreux pays ayant accueilli ces événements se sont retrouvés endettés, sans bénéfices réels pour leurs citoyens.</p>',2),(780,1178,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Grâce à la livraison en entreprise, les employés bénéficieront d\'un gain de temps notable. Il n\'est plus question d\'aller sortir loin du lieu de travail pour trouver de quoi manger. En complément, l\'argent et l\'énergie économisée permettent d\'être encore plus efficace au travail. Sans pour autant mettre fin à une session importante liée au travail, le repas sera déjà prêt et pourra attendre la fin d\'une conférence, d\'une réunion ou d\'un rendez-vous. Il s\'agit d\'une véritable solution dédiée aux entreprises ayant une activité intense et qui requiert la présence continue de leurs employés.</p>\r\n                    <p>Et en ce qui concerne les inconvénients ?</p>',1),(781,1178,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Cette pratique révèle souvent des inconvénients à cause de sa notoriété montante. Certains jours, il arrive que les responsables de livraisons peuvent être envahis par un grand nombre de livraisons à faire et cela risque de générer des perturbations liées au stress de l\'attente. De même pour les employés, une trop longue heure de travail peut causer un état de fatigue si ce dernier ne quittera pas son bureau pour le repas. Dans tous les cas, il est recommandé de toujours marquer des temps de pause lors des durs labeurs.</p>',2),(782,1181,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La télévision est un outil de communication et de divertissement largement répandu dans notre société moderne. Son influence est incontestable, tant sur les individus que sur la culture en général. Elle permet de diffuser des informations, d\'offrir des divertissements variés et de favoriser la diffusion de la culture. La télévision est présente dans de nombreux foyers et constitue une source d\'information et de divertissement accessibles à tous. Grâce à sa portée et à sa capacité à toucher un large public, la télévision joue un rôle important dans la transmission des connaissances et la sensibilisation aux enjeux sociaux.</p>',1),(783,1181,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La télévision peut également présenter certains inconvénients. Les émissions télévisées peuvent parfois véhiculer des stéréotypes, des préjugés et des valeurs discutables. De plus, le temps passé devant la télévision peut réduire le temps consacré à d\'autres activités plus enrichissantes, telles que la lecture, les interactions sociales ou la pratique d\'un sport. Il est important de faire preuve de discernement et de réguler l\'exposition à la télévision, en particulier pour les enfants, afin de préserver un équilibre sain entre les différentes formes d\'apprentissage et de divertissement.</p>',2),(784,1184,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amateurs ont fait des recettes réussies, mais ils manquent toujours des compétences et des technique, c\'est pourquoi la formations et l\'expérience sont nécessaires pour être un vrai cuisinier.</p>',1),(785,1184,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il parle des cuisiniers qui ont appris le métier de cuisiniers sur internet et qui ont le buzz sur les réseaux sociaux il raconte aussi l\'histoire d\'une amatrice qui est devenue professionnelle et qui a rédigé plusieurs livres sur la cuisine pour les amateurs de cuisine à la maison.</p>',2),(786,1187,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>La vie en colocation offre de nombreux avantages. Partager un logement avec d\'autres personnes permet de réduire les dépenses, que ce soit le loyer, les factures ou les frais généraux. De plus, cela favorise les interactions sociales et les échanges culturels. Vivre avec des colocataires permet de rencontrer des individus de différents horizons, de nouer des amitiés et de partager des expériences enrichissantes.</p>',1),(787,1187,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>La colocation peut cependant présenter des défis. Les différences de personnalité et de mode de vie entre les colocataires peuvent entraîner des tensions. La gestion des responsabilités et des tâches ménagères peut également être source de conflits. De plus, la colocation peut limiter l\'intimité et l\'espace personnel. Il est important d\'établir une communication ouverte et respectueuse, ainsi que des règles de vie commune, pour favoriser une cohabitation harmonieuse.</p>',2),(788,1190,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le travail est au centre de notre vie. Dès l\'enfance, on entend souvent la question: «Qu\'est-ce que tu veux faire quand tu seras grand ? ». Le travail devrait être synonyme de réussite et de satisfaction, mais il est trop souvent synonyme de fatigue et d\'emprisonnement. Aujourd\'hui, beaucoup pensent que l\'on ne passe pas assez de temps avec sa famille, ses amis. Il est urgent de revoir la place occupée par le travail dans notre société. Certains pensent que travailler moins permettrait d\'avoir plus de temps libre pour mieux vivre.</p>',1),(789,1190,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Certaines personnes ont décidé d\'arrêter de travailler pour changer de mode de vie. Pourtant, aujourd\'hui, travailler, c\'est exister La question : «Qu\'est-ce que tu fais dans la vie ?» revient souvent lors d\'une première rencontre. Elle prouve que l\'emploi fait partie de notre identité. D\'après le spécialiste Jean-Daniel Remond, la vie en entreprise est très importante. Les contacts quotidiens, les réseaux, les amitiés, l\'impression d\'être utile, mais aussi les difficultés, tout cela contribue à construire notre personnalité et notre identité.</p>',2),(790,1193,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les amitiés entre collègues au travail peuvent être extrêmement bénéfiques. Elles favorisent un climat de travail agréable et une ambiance positive au sein de l\'équipe. Avoir des amis parmi ses collègues permet de renforcer les liens professionnels et de créer un sentiment de camaraderie. Cela peut contribuer à une meilleure communication, une collaboration plus étroite et une résolution plus efficace des problèmes. De plus, partager des moments de convivialité en dehors du travail, comme des déjeuners ou des activités après le bureau peut renforcer les liens et créer une dynamique de groupe solide.</p>',1),(791,1193,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Il est important de trouver un équilibre entre amitié et professionnalisme au travail. Les amitiés excessivement proches peuvent parfois créer des tensions ou des conflits lorsque des décisions professionnelles doivent être prises. De plus, les amitiés exclusives entre certains collègues peuvent exclure les autres membres de l\'équipe, ce qui peut nuire à la cohésion et à la collaboration. Il est essentiel de maintenir des limites claires et de veiller à ce que les amitiés ne compromettent pas le professionnalisme, la hiérarchie ou la productivité au sein de l\'organisation.</p>',2),(792,1196,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Le dernier exemple vient d\'Oslo, la capitale norvégienne. Une responsable du projet annonce : « Ce sera mieux pour les piétons, les cyclistes, les commerces. Mieux pour tout le monde ». Moins de voitures, c\'est la reconquête de la ville par ses habitants. Les bénéfices pour la qualité de l\'air et pour l\'économie locale seront garantis.</p>',1),(793,1196,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le dernier exemple vient d\'Oslo, la capitale norvégienne. Une responsable du projet annonce : « Ce sera mieux pour les piétons, les cyclistes, les commerces. Mieux pour tout le monde ». Moins de voitures, c\'est la reconquête de la ville par ses habitants. Les bénéfices pour la qualité de l\'air et pour l\'économie locale seront garantis.</p>',2),(794,1199,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Franck soutient l\'utilisation limitée du plastique, soulignant son importance dans de nombreux secteurs, notamment médical et alimentaire. Pour lui, le plastique est vital pour la conservation des aliments et la stérilisation des équipements médicaux. Il prône une utilisation responsable et le recyclage, mais reconnaît que certains usages du plastique sont indispensables pour la société moderne.</p>',1),(795,1199,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Amicha s\'oppose fermement à l\'utilisation du plastique, mettant en avant son impact environnemental dévastateur. Elle argue que les déchets plastiques polluent les océans et les écosystèmes, causant des dommages irréparables. Amicha milite pour des alternatives écologiques et durables, insistant sur l\'urgence de renoncer au plastique pour protéger l\'environnement et la santé publique.</p>',2),(796,1202,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Depuis plusieurs années maintenant, de nombreux lecteurs ont décidé de remplacer la bibliothèque traditionnelle par des livres numériques. Selon eux, l\'avantage est avant tout économique. D\'une part, le livre numérique permet d\'économiser du papier, d\'autre part la version numérique d\'un livre est généralement moins chère que la version papier. Les livres numériques ont un autre avantage : ils permettent une ouverture sur le monde pour les personnes en situation de handicap. Certaines options, comme la possibilité d\'augmenter la taille des lettres, facilitent la lecture pour les personnes malvoyantes.</p>',1),(797,1202,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Le livre numérique remplacera-t-il le livre papier ? \"Non\", répondront la plupart des lecteurs. Le livre papier est un beau support. Quel plaisir de le prêter aux gens qu\'on aime ou de l\'offrir en glissant un petit mot dedans ! Le livre papier a une histoire, l\'odeur du neuf ou de l\'ancien… Il transmet beaucoup d\'émotions alors que le livre numérique à un côté un peu impersonnel. De plus, les livres numériques demandent de posséder un minimum de connaissances en informatique, ce qui peut être une difficulté pour certaines personnes.</p>',2),(798,1205,1,NULL,'<p><strong>Document 1 :</strong></p>\r\n                    <p>Les habitudes alimentaires modernes ont permis de diversifier notre alimentation et d\'améliorer la santé. L\'accès à une grande variété d\'aliments, notamment des fruits, des légumes, et des produits enrichis, a réduit les carences nutritionnelles. Cette évolution a contribué à augmenter l\'espérance de vie dans de nombreux pays et favorise une prévention des maladies grâce à une alimentation plus équilibrée.</p>',1),(799,1205,2,NULL,'<p><strong>Document 2 :</strong></p>\r\n                    <p>Les nouvelles habitudes alimentaires sont parfois nocives pour la santé. La consommation accrue de produits transformés, riches en sucre, sel et graisses, a mené à une hausse des problèmes d\'obésité et de maladies cardiaques. De plus, l\'habitude de manger rapidement sans cuisiner contribue à la perte des traditions culinaires et réduit la convivialité des repas.</p>',2),(800,0,1,'Document 1','<p>Les maisons de retraite représentent une solution adaptée pour les personnes âgées. Elles y bénéficient de soins appropriés et d&#039;un encadrement professionnel. En plus, elles ont la possibilité de participer à diverses activités qui leur permettent de garder une vie sociale et d&#039;éviter la solitude. Dans certains cas, c&#039;est mieux que de rester seules chez elles. (Sophie, infirmière)</p>',1),(801,0,2,'Document 2','<p>Les maisons de retraite peuvent priver les personnes âgées de la présence de leur famille et donner l&#039;impression d&#039;être abandonnées. De plus, les conditions de vie ne sont pas toujours satisfaisantes et certains établissements manquent parfois de personnel compétent. Selon moi, l&#039;aide à domicile est une meilleure solution pour vieillir auprès de ses proches. (Jean, retraité)</p>',2),(802,0,1,'Document 1','<p>Les restaurants de restauration rapide offrent une gamme variée de plats équilibrés tout en respectant les normes d&#039;hygiène. Le client, ayant la liberté de composer son propre menu, assume ainsi la responsabilité de ses choix alimentaires.</p>',1),(803,0,2,'Document 2','<p>La consommation fréquente de restauration rapide peut avoir des effets néfastes sur la santé, contribuant à l&#039;apparition de problèmes graves et irréversibles tels que l&#039;obésité et d&#039;autres maladies associées.</p>',2),(804,0,1,'Document 1','<p>Jean qui vit à la campagne favorise l&#039;achat des produits alimentaires directement à la ferme pour la bonne qualité, quitte à payer un peu plus cher.</p>',1),(805,0,2,'Document 2','<p>Camille qui vit dans la ville préfère faire ses courses au supermarché pour la variété qu&#039;il propose et pour les prix abordables.</p>',2),(806,0,1,'Document 1','<p>Je suis de ceux qui n&#039;arrivent pas à comprendre comment l&#039;on peut prendre du plaisir à tuer des animaux. Je suis de ceux qui n&#039;arrivent pas à comprendre comment on peut prétendre aimer la nature alors qu&#039;on la détruit.</p>',1),(807,0,2,'Document 2','<p>Les gens chassent pour différentes raisons : la subsistance, le commerce, la conservation et l&#039;aménagement de la faune, la protection de la propriété, l&#039;exercice, le loisir et le prestige.</p>',2),(808,0,1,'Document 1','<p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d&#039;hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(809,0,2,'Document 2','<p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l&#039;environnement.</p>',2),(810,0,1,'Document 1','<p>Les vêtements de marque sont très importants pour les enfants et les adolescents. C&#039;est un moyen de s&#039;exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marque avec des images de dessins animés qu&#039;ils regardent ou des logos qu&#039;ils apprécient.</p>',1),(811,0,2,'Document 2','<p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l&#039;extérieur avec les copains, en s&#039;amusant dans l&#039;herbe ou à l&#039;aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(812,0,1,'Document 1','<p>La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer plus de temps à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress, améliorant ainsi leur productivité globale.</p>',1),(813,0,2,'Document 2','<p>Réduire les heures de travail peut aider les entreprises en réduisant l&#039;absentéisme et en augmentant la fidélisation des employés. En offrant des horaires plus flexibles, les employés sont généralement plus motivés et impliqués. Cependant, cela nécessite une organisation efficace et une adaptation des processus pour maintenir la productivité et répondre aux besoins de l&#039;entreprise.</p>',2),(814,0,1,'Document 1','<p>Dans l&#039;école où j&#039;enseigne à Montréal, les caméras de surveillance sont omniprésentes. Leur présence permet de dissuader les élèves de commettre des actes de violence. Les enseignants, les parents et la majorité des élèves les acceptent volontiers, car ils se sentient rassurés quant à la sécurité des enfants et cela permet aux enseignants de travailler dans de bonnes conditions. Toutefois, certains élèves considèrent que cela porte atteinte à leur vie privée.</p>',1),(815,0,2,'Document 2','<p>Je suis opposé à l&#039;installation des caméras de surveillance dans nos écoles à Montréal. Les résultats obtenus dans les pays où ce système est utilisé ne sont pas convaincants. Les personnes mal intentionnées peuvent facilement contourner les caméras, qui sont très visibles. Les problèmes de discipline dans une école peuvent être résolus en améliorant la communication entre les enseignants, l&#039;administration et les élèves. Il est également nécessaire de faire respecter et expliquer les règles de l&#039;école par tous, plutôt que de recourir aux caméras.</p>',2),(816,0,1,'Document 1','<p>Grâce à l&#039;art, la curiosité des citadins est attisée dans l&#039;espace urbain. Que ce soit par une peinture ou un spectacle de rue, l&#039;atmosphère éphémère ainsi créée offre une interaction entre des artistes peu connus et un public hétéroclite, parfois peu habitué à côtoyer cette forme d&#039;art. Les villes d&#039;aujourd&#039;hui n&#039;ont plus la même vocation que celles d&#039;hier. Plus qu&#039;un lieu de résidence, la ville se réinvente, s&#039;enrichit de la diversité de sa population, s&#039;agence différemment et s&#039;ouvre sur le monde. Les espaces verts se créent et les murs se parent de couleurs grâce au street art. Cela débouche sur des lieux où la qualité de vie est privilégiée, tout en respectant la nature et l&#039;environnement.</p>',1),(817,0,2,'Document 2','<p>Mais à une plus large échelle, cela n&#039;est pas aussi évident. Les graffitis peuvent être perçus comme une dégradation de la communauté, une pollution visuelle ou une preuve de la rupture sociale. On les considère comme du vandalisme qui défigure les biens publics. Le débat sur les avantages et les inconvénients des graffitis fait rage parmi les artistes, les législateurs et les membres de la communauté.</p>',2),(818,0,1,'Document 1','<p>Les objets intelligents rendent notre quotidien plus pratique. Ce sont des appareils qui peuvent être contrôlés à distance par un téléphone ou Internet, comme le chauffage ou les systèmes de sécurité de la maison. Par ailleurs, des objets tels que les montres ou bracelets connectés suivent nos activités et nous motivent à faire plus d&#039;exercice, en mesurant par exemple nos pas. Leur utilité est particulièrement notable dans le domaine de la santé. Certains objets agissent comme un assistant santé, nous rappelant les rendez-vous médicaux ou la prise de nos médicaments.</p>',1),(819,0,2,'Document 2','<p>On estime qu&#039;il y aurait 50 milliards d&#039;objets intelligents dans le monde, tels que des alarmes, des téléviseurs, des caméras de surveillance, des volets ou des détecteurs de fumée, entre autres. Avec cette expansion, la question de la sécurité devient cruciale. En effet, un hacker pourrait prendre le contrôle de ces appareils en quelques minutes. Par exemple, un cambrioleur pourrait, grâce aux caméras de surveillance connectées, vérifier si les habitants sont absents avant de commettre un cambriolage. Il est même possible d&#039;accéder au système connecté d&#039;une voiture et de la contrôler à distance.</p>',2),(820,0,1,'Document 1','<p>L&#039;accès gratuit aux musées peut engendrer une affluence excessive, altérant ainsi la qualité de la visite. De plus, cela risque de diminuer leurs revenus, compromettant l&#039;entretien des lieux et la conservation des œuvres. Une tarification réduite serait une alternative équilibrée pour favoriser l&#039;accès à la culture tout en assurant le bon fonctionnement des musées.</p>',1),(821,0,2,'Document 2','<p>Rendre les musées gratuits est une excellente initiative, car cela permet à tous d&#039;accéder à la culture, quel que soit leur revenu. J&#039;ai eu l&#039;opportunité de visiter plusieurs musées sans frais, ce qui m&#039;a permis d&#039;enrichir mes connaissances sans me préoccuper du coût. À mon avis, la gratuité des musées joue un rôle clé dans l&#039;éducation du public et la diffusion du patrimoine culturel.</p>',2),(822,0,1,'Document 1','<p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d&#039;hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(823,0,2,'Document 2','<p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l&#039;environnement.</p>',2),(824,0,1,'Document 1','<p>D&#039;après une enquête, les enfants sont en permanence confrontés à de nombreuses publicités diffusées à la télévision, dans les journaux ou sur Internet, souvent dans des espaces où ils sont vulnérables. Celles-ci ciblent principalement les jouets, les jeux vidéo et les aliments peu sains, ce qui influence leurs décisions et leurs demandes familiales.</p>',1),(825,0,2,'Document 2','<p>Un travail de recherche paru dans une revue scientifique montre que les enfants comprennent difficilement les messages publicitaires, même s&#039;ils savent généralement que leur but est de persuader. Pourtant, d&#039;autres facteurs comme l&#039;éducation reçue des parents, la société et la culture ont un poids plus fort sur leurs choix de consommation que la publicité.</p>',2),(826,0,1,'Document 1','<p>Selon moi, vivre en ville offre beaucoup d&#039;occasions de se divertir : aller au cinéma, manger dans un restaurant, faire les magasins… Tout est accessible sans devoir parcourir de longues distances ni chercher un taxi pour un trajet. On trouve facilement tout ce dont on a besoin. De plus, les amateurs de culture y trouvent aussi leur bonheur : musées, théâtres, opéras… tout est présent !</p>',1),(827,0,2,'Document 2','<p>Récemment, j&#039;ai choisi de quitter la vie urbaine pour m&#039;installer à la campagne, car je ressentais le besoin de me rapprocher de la nature et de profiter de la tranquillité. Aujourd&#039;hui, au lieu de sortir chaque jour dans un café ou un restaurant, je préfère inviter mes amis sur ma terrasse ou organiser parfois un barbecue dans mon jardin. Une autre raison qui m&#039;a poussé à faire ce choix, c&#039;est le prix des logements : à la campagne, les maisons sont beaucoup plus abordables. Avec mon budget actuel, je profite d&#039;une grande maison avec terrasse et jardin, alors qu&#039;en ville je n&#039;avais qu&#039;un petit appartement au cinquième étage.</p>',2),(828,0,1,'Document 1','<p>Beaucoup de jeunes sortant de l&#039;université se retrouvent sans emploi. La valeur des diplômes sur le marché du travail pose des questions. Souvent, les recruteurs leur reprochent d&#039;avoir trop étudié et trop peu d&#039;expérience, ou considèrent leur jeunesse comme un frein. Plus de 60 % des diplômés restent sans travail un an après leurs études. Il paraît donc urgent de mieux reconnaître les diplômes et de faciliter l&#039;insertion professionnelle.</p>',1),(829,0,2,'Document 2','<p>On parle souvent de dirigeants célèbres qui ont réussi sans suivre de cursus universitaire. Ces exemples peuvent laisser penser qu&#039;il suffit d&#039;être talentueux pour diriger une entreprise. Certains chefs d&#039;entreprise considèrent même que l&#039;université peut freiner la créativité. Selon eux, elle pousse les étudiants à suivre des parcours standards et limite l&#039;innovation. Pour les futurs entrepreneurs, rien ne remplacerait l&#039;expérience pratique et l&#039;autoformation, sans dépendre d&#039;une institution académique.</p>',2),(830,0,1,'Document 1','<p>Faire une sieste au travail présente de nombreux bénéfices pour les salariés et les entreprises. Permettre aux employés de se reposer quelques minutes peut accroître leur productivité et améliorer leur santé et leur bien-être. Les courtes siestes renforcent la concentration, diminuent le stress et améliorent l&#039;humeur. Elles peuvent aussi réduire les coûts liés à la fatigue et aux accidents. Les entreprises devraient donc envisager d&#039;intégrer cette pratique pour leur personnel.</p>',1),(831,0,2,'Document 2','<p>Même si la sieste au travail présente de nombreux bénéfices, il n&#039;est pas facile pour toutes les entreprises d&#039;aménager des espaces ou des lits pour cela. Les contraintes financières, logistiques ou les règles strictes peuvent empêcher les salariés de se reposer. De plus, certains employés peuvent se sentir mal à l&#039;aise. Il est donc important que les entreprises évaluent avantages et limites et trouvent des solutions pour favoriser le repos.</p>',2),(832,0,1,'Document 1','<p>Les maisons de retraite représentent une solution adaptée pour les personnes âgées. Elles y bénéficient de soins appropriés et d&#039;un encadrement professionnel. En plus, elles ont la possibilité de participer à diverses activités qui leur permettent de garder une vie sociale et d&#039;éviter la solitude. Dans certains cas, c&#039;est mieux que de rester seules chez elles. (Sophie, infirmière)</p>',1),(833,0,2,'Document 2','<p>Les maisons de retraite peuvent priver les personnes âgées de la présence de leur famille et donner l&#039;impression d&#039;être abandonnées. De plus, les conditions de vie ne sont pas toujours satisfaisantes et certains établissements manquent parfois de personnel compétent. Selon moi, l&#039;aide à domicile est une meilleure solution pour vieillir auprès de ses proches. (Jean, retraité)</p>',2),(834,0,1,'Document 1','<p>Les restaurants de restauration rapide offrent une gamme variée de plats équilibrés tout en respectant les normes d&#039;hygiène. Le client, ayant la liberté de composer son propre menu, assume ainsi la responsabilité de ses choix alimentaires.</p>',1),(835,0,2,'Document 2','<p>La consommation fréquente de restauration rapide peut avoir des effets néfastes sur la santé, contribuant à l&#039;apparition de problèmes graves et irréversibles tels que l&#039;obésité et d&#039;autres maladies associées.</p>',2),(836,0,1,'Document 1','<p>Jean qui vit à la campagne favorise l&#039;achat des produits alimentaires directement à la ferme pour la bonne qualité, quitte à payer un peu plus cher.</p>',1),(837,0,2,'Document 2','<p>Camille qui vit dans la ville préfère faire ses courses au supermarché pour la variété qu&#039;il propose et pour les prix abordables.</p>',2),(838,0,1,'Document 1','<p>Je suis de ceux qui n&#039;arrivent pas à comprendre comment l&#039;on peut prendre du plaisir à tuer des animaux. Je suis de ceux qui n&#039;arrivent pas à comprendre comment on peut prétendre aimer la nature alors qu&#039;on la détruit.</p>',1),(839,0,2,'Document 2','<p>Les gens chassent pour différentes raisons : la subsistance, le commerce, la conservation et l&#039;aménagement de la faune, la protection de la propriété, l&#039;exercice, le loisir et le prestige.</p>',2),(840,0,1,'Document 1','<p>Les restaurants rapides se distinguent par leur engagement à proposer une variété de plats équilibrés, respectant strictement les normes d&#039;hygiène. En laissant aux clients la liberté de composer leur propre menu, ces établissements les responsabilisent dans leurs choix alimentaires, tout en satisfaisant leurs préférences gustatives.</p>',1),(841,0,2,'Document 2','<p>Les spécialistes affirment que manger régulièrement dans des restaurants de fast-food, qui proposent de la restauration rapide, est dangereux pour la santé. La nourriture servie est souvent la même : frites, hamburgers et boissons sucrées. Ces aliments contiennent une grande quantité de calories, bien trop pour un seul repas. De plus, la plupart des produits dans ces restaurants sont emballés dans du plastique. Par conséquent, manger dans un fast-food augmente la production de déchets plastiques, ce qui est nuisible pour l&#039;environnement.</p>',2),(842,0,1,'Document 1','<p>Les vêtements de marque sont très importants pour les enfants et les adolescents. C&#039;est un moyen de s&#039;exprimer et de se rattacher à un groupe social. Cette attirance pour les marques est très présente chez les adolescents qui se cherchent et montrent leur personnalité. Les enfants aiment également porter des vêtements de marque avec des images de dessins animés qu&#039;ils regardent ou des logos qu&#039;ils apprécient.</p>',1),(843,0,2,'Document 2','<p>Les enfants grandissent très vite et les vêtements sont portés pendant une courte période. Ainsi, les vêtements deviennent rapidement trop petits. Mais il y a aussi le fait que les enfants usent assez rapidement les vêtements en jouant à l&#039;extérieur avec les copains, en s&#039;amusant dans l&#039;herbe ou à l&#039;aire de jeux. Les habits sont très vite sales ou troués.</p>',2),(844,0,1,'Document 1','<p>La réduction du temps de travail permet aux employés de mieux équilibrer leur vie professionnelle et personnelle. En travaillant moins, ils peuvent consacrer plus de temps à leur famille, à leurs loisirs et à leur santé. Cela peut également augmenter leur satisfaction au travail et réduire le stress