LOCK TABLES `tcf_ee_consignes` WRITE;
/*!40000 ALTER TABLE `tcf_ee_consignes` DISABLE KEYS */;
INSERT IGNORE INTO `tcf_ee_consignes` (`id`, `title`, `body`, `task_key`, `visibility`, `is_published`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (15,'Instructions générales','L\'épreuve d\'expression écrite du TCF Canada évalue votre capacité à vous exprimer en français dans des situations de la vie quotidienne.\nCette épreuve comprend 3 tâches de difficulté progressive qui simulent des situations réelles de communication.','general','gratuit',1,1,1,'2026-05-09 08:33:25',NULL),(16,'Important','Vous disposerez de 15 minutes de préparation avant l\'épreuve.\nPendant l\'épreuve, chaque temps de parole est strictement chronométré.\nL\'examinateur enregistrera vos réponses pour évaluation.','general','gratuit',1,2,1,'2026-05-09 08:33:25',NULL),(20,'Critères d\'évaluation','Correction grammaticale : maîtrise des structures de base de la langue.\nRichesse lexicale : étendue et précision du vocabulaire utilisé.\nPrononciation : clarté de l\'articulation et intonation.\nMaîtrise discursive : capacité à organiser et enchaîner ses idées.\nInteraction : capacité à comprendre et réagir aux sollicitations.','general','gratuit',1,6,1,'2026-05-09 08:33:25',NULL),(21,'Conseil 1','Gérez bien votre temps de préparation : notez des idées clés, pas des phrases entières.','general','gratuit',1,7,1,'2026-05-09 08:33:25',NULL),(22,'Conseil 2','Parlez distinctement et à un rythme naturel, ni trop vite ni trop lentement.','general','gratuit',1,8,1,'2026-05-09 08:33:25',NULL),(23,'Conseil 3','Utilisez des formules de politesse adaptées aux situations proposées et variez les structures grammaticales.','general','gratuit',1,9,1,'2026-05-09 08:33:25',NULL),(24,'Conseil 4','Structurez vos réponses : introduction, développement, conclusion (surtout pour la tâche 3).','general','gratuit',1,10,1,'2026-05-09 08:33:25',NULL),(25,'Tâche 1','<h2>Consignes pour l\'épreuve d\'Expression Écrite</h2>\n\n<div class=\"consigne-section\">\n    <h3>📋 Informations générales</h3>\n    <ul>\n        <li><strong>Durée :</strong> 60 minutes</li>\n        <li><strong>Nombre de tâches :</strong> 3 tâches</li>\n        <li><strong>Support :</strong> Documents écrits (lettres, emails, articles)</li>\n        <li><strong>Objectif :</strong> Évaluer votre capacité à produire des écrits en français</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>📚 Structure de l\'épreuve</h3>\n    <p>L\'épreuve se compose de trois tâches progressives :</p>\n    \n    <h4>Tâche 1 : Écrire un message (15 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Situation de la vie quotidienne ou professionnelle</li>\n        <li><strong>Type :</strong> Lettre, email, message</li>\n        <li><strong>Longueur :</strong> Environ 50 mots</li>\n        <li><strong>Objectif :</strong> Transmettre une information simple</li>\n    </ul>\n    \n    <h4>Tâche 2 : Rédiger un texte argumentatif (45 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Sujet d\'actualité ou problème de société</li>\n        <li><strong>Type :</strong> Article, essai, opinion</li>\n        <li><strong>Longueur :</strong> Environ 180 mots</li>\n        <li><strong>Objectif :</strong> Exprimer et défendre un point de vue</li>\n    </ul>\n    \n    <h4>Tâche 3 : Synthèse de documents (60 minutes)</h4>\n    <ul>\n        <li><strong>Contexte :</strong> Deux ou trois documents sur un même thème</li>\n        <li><strong>Type :</strong> Synthèse écrite</li>\n        <li><strong>Longueur :</strong> Environ 250 mots</li>\n        <li><strong>Objectif :</strong> Résumer et comparer les informations</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>💡 Conseils pour réussir</h3>\n    <ul>\n        <li>Lisez attentivement le sujet et repérez les mots-clés</li>\n        <li>Respectez scrupuleusement le nombre de mots demandé</li>\n        <li>Structurez votre texte : introduction, développement, conclusion</li>\n        <li>Utilisez des connecteurs logiques (cependant, par conséquent, en effet)</li>\n        <li>Variez le vocabulaire et les structures grammaticales</li>\n        <li>Relisez votre texte pour corriger les fautes d\'orthographe</li>\n        <li>Adaptez votre ton au contexte (formel ou informel)</li>\n    </ul>\n</div>\n\n<div class=\"consigne-section\">\n    <h3>🎯 Critères d\'évaluation</h3>\n    <ul>\n        <li><strong>Respect du sujet :</strong> Répondre à la question posée</li>\n        <li><strong>Cohérence :</strong> Organisation logique du texte</li>\n        <li><strong>Richesse lexicale :</strong> Vocabulaire varié et précis</li>\n        <li><strong>Correction grammaticale :</strong> Syntaxe et conjugaison</li>\n        <li><strong>Orthographe :</strong> Respect des règles d\'écriture</li>\n    </ul>\n</div>','tache1','gratuit',1,1,1,'2026-05-09 11:03:04','2026-07-11 20:45:17'),(26,'Tâche 2','Vous devrez obtenir des informations dans une situation de la vie courante (2 minutes 30).\r\nCette tâche évalue votre capacité à interagir dans un contexte pratique.','tache2','gratuit',1,2,1,'2026-05-09 11:03:04',NULL),(27,'Tâche 3','Vous présenterez votre opinion sur un sujet donné (3 minutes 30).\r\nCette partie évalue votre capacité à argumenter et à structurer votre discours.','tache3','gratuit',1,3,1,'2026-05-09 11:03:04',NULL);
