INSERT IGNORE INTO `tcf_eo_subjects` (`id`, `part_id`, `subject_number`, `title`, `prompt`, `correction`, `role_label`, `icon_class`, `created_at`, `updated_at`) VALUES (6,2,1,'Voyages organisés','Je suis votre ami(e) et je fais régulièrement des voyages organisés. Vous voulez partir en vacances de cette façon. Vous me demandez des conseils pour organiser votre voyage (destination, prix, activités, etc.).',NULL,NULL,'bx bx-trip','2026-05-09 12:34:05','2026-05-09 12:34:05'),(7,2,2,'Cours de dessin','Je suis votre ami(e). Je prends des cours de dessin. Vous êtes intéressé(e) et vous me posez des questions pour avoir des informations (les tarifs, l\'école, les professeurs, les horaires, etc.).',NULL,NULL,'bx bx-palette','2026-05-09 12:34:05','2026-05-09 12:34:05'),(8,2,3,'Découverte de la ville','Je suis votre ami(e). Vous venez de vous installer dans ma ville. Vous voulez sortir le week-end. Vous me posez des questions pour connaître les quartiers animés, les activités à faire, les lieux à visiter, etc.',NULL,NULL,'bx bx-map','2026-05-09 12:34:05','2026-05-09 12:34:05'),(9,2,4,'Week-end en ville','Je suis votre ami(e). Vous voulez passer un week-end dans une ville que je connais bien. Pour organiser votre séjour. Vous me posez des questions sur cette ville (lieux à visiter, météo, activités, hébergement, etc.)',NULL,NULL,'bx bx-building','2026-05-09 12:34:05','2026-05-09 12:34:05'),(10,2,5,'Bibliothèque','Je travaille à l\'accueil d\'une bibliothèque. Vous voulez vous inscrire. Vous me posez des questions sur le fonctionnement de cette bibliothèque (inscription, conditions d\'emprunt, horaires, etc.).',NULL,NULL,'bx bx-book','2026-05-09 12:34:05','2026-05-09 12:34:05'),(11,3,1,'Baby-sitter','Je suis votre ami(e). J\'emploie un(e) baby-sitter toutes les semaines. Vous cherchez quelqu\'un pour garder votre enfant. Vous me posez des questions sur ma baby-sitter (disponibilité, tarifs, activités avec les enfants, …)',NULL,NULL,'bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(12,3,2,'Vie au Canada','Je travaille dans une association franco-canadienne. Vous souhaitez vous installer au Canada. Vous me posez des questions pour savoir comment vivent les Canadiens (travail, loisirs, logement, etc.).',NULL,NULL,'bx bx-flag','2026-05-09 12:34:05','2026-05-09 12:34:05'),(13,3,3,'Garde d\'animal','Je suis votre ami(e). Je cherche une personne pour garder mon animal pendant mes vacances. Vous me posez des questions pour obtenir des informations (dates, activités, soins, …).',NULL,NULL,'bx bx-dog','2026-05-09 12:34:05','2026-05-09 12:34:05'),(14,3,4,'Randonnées Toronto','Je suis votre voisin(e). Je travaille dans une agence qui organise des randonnées dans la forêt autour de Toronto. Vous êtes intéressé(e) et vous me posez des questions sur cette activité (circuits, tarifs, participants, etc.).',NULL,NULL,'bx bx-walk','2026-05-09 12:34:05','2026-05-09 12:34:05'),(15,3,5,'Vie en immeuble','Je suis votre voisin(e). Vous venez de vous installer dans l\'immeuble. Vous me posez des questions sur l\'organisation de l\'immeuble (habitants, règles de vie, équipements, etc.).',NULL,NULL,'bx bx-building-house','2026-05-09 12:34:05','2026-05-09 12:34:05'),(16,4,1,'Auto-école','Je travaille dans une auto-école, vous voulez apprendre à conduire. Vous me posez des questions pour avoir des informations.',NULL,NULL,'bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(17,4,2,'Cours de langue','Je suis votre collègue, je fais des cours de langue payés par l\'entreprise, vous êtes intéressé. Posez moi des questions (langues, qualité, horaires, etc.).',NULL,NULL,'bx bx-globe','2026-05-09 12:34:05','2026-05-09 12:34:05'),(18,4,3,'Location de voiture','Je travaille dans une agence de location de voiture, vous avez besoin d\'en louer une. Posez moi des questions (offre, prix, procédure, etc.).',NULL,NULL,'bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(19,4,4,'Colocation','Je partage un appartement avec des colocataires, une chambre est libre, cela vous intéresse. Posez moi des question pour avoir des renseignement (loyer, prix, etc.).',NULL,NULL,'bx bx-home','2026-05-09 12:34:05','2026-05-09 12:34:05'),(20,4,5,'Mariage','Je suis votre ami(e), mon fils va se marier, vous êtes invité(e). Posez-moi des questions (invités, cadeau, organisation, etc.).',NULL,NULL,'bx bx-heart','2026-05-09 12:34:05','2026-05-09 12:34:05'),(21,5,1,'Bénévolat associatif','Je suis agent d\'accueil dans un bureau d\'information sur les associations de la ville. Vous voulez être bénévole dans une association de votre quartier. Vous me posez des questions (types, activités, publics, planning, etc.).',NULL,NULL,'bx bx-group','2026-05-09 12:34:05','2026-05-09 12:34:05'),(22,5,2,'Cours de français','Je suis professeur de français. Vous venez d\'arriver au Canada, vous voulez prendre des cours particuliers. Vous m\'interrogez sur mon parcours professionnel (expérience, méthodes, tarifs, etc.).',NULL,NULL,'bx bx-book','2026-05-09 12:34:05','2026-05-09 12:34:05'),(23,5,3,'Vacances à la montagne','Je suis un(e) ami(e) canadien(ne). Je viens de passer des vacances formidables à la montagne. Vous voulez faire la même chose. Vous me posez des questions sur mon séjour (lieu, activités, hébergement, etc.).',NULL,NULL,'bx bx-landscape','2026-05-09 12:34:05','2026-05-09 12:34:05'),(24,5,4,'Cours de théâtre','Je suis votre ami(e). Je prends des cours de théâtre toutes les semaines. Vous voulez vous inscrire à ces cours. Vous me posez des questions pour avoir des informations (tarifs, horaires, organisation, etc.).',NULL,NULL,'bx bx-theatre','2026-05-09 12:34:05','2026-05-09 12:34:05'),(25,5,5,'Apéritif de bienvenue','Vous venez d\'arriver au Québec. Je suis votre voisin(e). Je vous ai invité(e) à un apéritif de bienvenue. Pendant l\'apéritif, vous me posez des questions pour avoir des informations sur la vie du quartier (voisins, services, activités, etc.).',NULL,NULL,'bx bx-party','2026-05-09 12:34:05','2026-05-09 12:34:05'),(26,6,1,'Changer de pays, changer de culture','Changer de pays, c\'est changer de culture. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-globe','2026-05-09 12:34:05','2026-05-09 12:34:05'),(27,6,2,'Politesse des jeunes','De nos jours, les jeunes sont de moins en moins polis. Êtes-vous d\'accord ? Pourquoi ?',NULL,NULL,'bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(28,6,3,'Vivre seul(e)','Il est difficile de vivre seul(e). Êtes-vous d\'accord ?',NULL,NULL,'bx bx-user','2026-05-09 12:34:05','2026-05-09 12:34:05'),(29,6,4,'Se faire des amis à l\'étranger','À votre avis, est-il facile de se faire des amis quand on s\'installe dans un nouveau pays ? Pourquoi ?',NULL,NULL,'bx bx-group','2026-05-09 12:34:05','2026-05-09 12:34:05'),(30,6,5,'Vivre sans Internet','À votre avis, peut-on vivre sans Internet ? Pourquoi ?',NULL,NULL,'bx bx-wifi','2026-05-09 12:34:05','2026-05-09 12:34:05'),(31,7,1,'Transports en commun gratuits','Les transports en commun doivent être gratuits en ville. Est-ce une bonne idée selon vous ?',NULL,NULL,'bx bx-bus','2026-05-09 12:34:05','2026-05-09 12:34:05'),(32,7,2,'Contrôle parental','Les parents doivent contrôler les fréquentations de leurs enfants. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-group','2026-05-09 12:34:05','2026-05-09 12:34:05'),(33,7,3,'Tourisme et environnement','Le développement du tourisme est contraire à la protection de l\'environnement. Qu\'en pensez-vous?',NULL,NULL,'bx bx-tree','2026-05-09 12:34:05','2026-05-09 12:34:05'),(34,7,4,'Vivre sans parler la langue','Il est possible de vivre dans un pays sans en parler la langue. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-globe','2026-05-09 12:34:05','2026-05-09 12:34:05'),(35,7,5,'Changer de métier','De nos jours, il est possible de changer de métier à tout âge. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-briefcase','2026-05-09 12:34:05','2026-05-09 12:34:05'),(36,8,1,'Connaître les cultures sans voyager','On peut connaitre les autres cultures sans voyager. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-globe','2026-05-09 12:34:05','2026-05-09 12:34:05'),(37,8,2,'Produits bio','Consommer des produits bio est réservé aux personnes les plus riches. Êtes vous d\'accord? Pourquoi?',NULL,NULL,'bx bx-leaf','2026-05-09 12:34:05','2026-05-09 12:34:05'),(38,8,3,'Télévision et développement','La télévision participe au développement des enfants. Qu\'en pensez vous ?',NULL,NULL,'bx bx-tv','2026-05-09 12:34:05','2026-05-09 12:34:05'),(39,8,4,'Salaire et travail','La chose la plus importante dans un travail c\'est le salaire. Qu\'en pensez-vous ?',NULL,NULL,'bx bx-money','2026-05-09 12:34:05','2026-05-09 12:34:05'),(40,8,5,'Interdiction des voitures en ville','Faut-il interdire les voitures dans les centres villes ? Qu\'en pensez vous ?',NULL,NULL,'bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(41,9,1,'Internet et éducation','Internet a un impact positif dans l\'éducation des enfants. Qu\'en pensez-vous?',NULL,NULL,'bx bx-wifi','2026-05-09 12:34:05','2026-05-09 12:34:05'),(42,9,2,'Paraître jeune','La plupart des gens veulent paraître jeune que leur âge. Q\'en pensez-vous?',NULL,NULL,'bx bx-body','2026-05-09 12:34:05','2026-05-09 12:34:05'),(43,9,3,'Tourisme et développement','Le tourisme contribue à la croissance et au développement du pays. Êtes-vous d\'accord avec cette affirmation?',NULL,NULL,'bx bx-trip','2026-05-09 12:34:05','2026-05-09 12:34:05'),(44,9,4,'Jeux vidéos','Les jeux vidéos sont dangereux. Qu\'en pensez vous?',NULL,NULL,'bx bx-joystick','2026-05-09 12:34:05','2026-05-09 12:34:05'),(45,9,5,'Diplômes et réussite','Les diplômes sont indispensables dans la réussite professionnelle. Êtes-vous d\'accord avec cette affirmation?',NULL,NULL,'bx bx-certification','2026-05-09 12:34:05','2026-05-09 12:34:05'),(46,10,1,'Randonnée','Je travaille dans une agence de tourisme, vous voulez faire de la randonnée. Posez moi des questions (organisation, activités, participants).',NULL,'Rôle: Agent de tourisme','bx bx-hiking','2026-05-09 12:34:05','2026-05-09 12:34:05'),(47,10,2,'Recherche d\'emploi','Je travaille dans une agence d\'emploi. Vous venez de vous installer au Canada et vous cherchez un emploi. Posez moi des questions.',NULL,'Rôle: Agent d\'emploi','bx bx-briefcase','2026-05-09 12:34:05','2026-05-09 12:34:05'),(48,10,3,'Nouvelle ville','Je suis votre ami(e). J\'ai passé une semaine dans une nouvelle ville. Posez-moi des questions sur la ville.',NULL,'Rôle: Ami','bx bx-building','2026-05-09 12:34:05','2026-05-09 12:34:05'),(49,10,4,'Émission télévisée','Je suis votre ami(e), j\'ai participé à une émission télévisée. Posez moi des questions sur cette expérience (inscription, ambiance, etc.).',NULL,'Rôle: Ami','bx bx-tv','2026-05-09 12:34:05','2026-05-09 12:34:05'),(50,10,5,'Stage de sport','Je suis professeur de sport (gymnastique, yoga, etc.). J\'organise un stage le week-end prochain. Vous êtes intéressé(e). Vous me posez des questions sur le stage (lieu, niveau, stagiaires, etc.).',NULL,'Rôle: Professeur de sport','bx bx-dumbbell','2026-05-09 12:34:05','2026-05-09 12:34:05'),(51,11,1,'Article sur un film','Je suis un(e) ami(e) francophone. Vous devez écrire un article sur un film pour la revue de votre association culturelle francophone. Vous cherchez des idées. Vous m\'interrogez sur les films que j\'ai aimés (genre, lieu, prix, etc.).',NULL,'Rôle: Ami francophone','bx bx-movie','2026-05-09 12:34:05','2026-05-09 12:34:05'),(52,11,2,'Voyage touristique','Je suis un(e) employé(e) dans une agence de voyages. Vous voulez faire un voyage touristique. Vous entrez dans mon agence de voyages. Vous me demandez des informations sur les destinations (circuits touristiques, tarifs, activités, etc.).',NULL,'Rôle: Employé d\'agence de voyages','bx bx-trip','2026-05-09 12:34:05','2026-05-09 12:34:05'),(53,11,3,'Fête entre voisins','Je suis votre voisin(e). Vous souhaitez organiser une fête entre voisins. Vous me demandez des conseils pour l\'organisation (invités, type de repas, musique, etc.).',NULL,'Rôle: Voisin','bx bx-party','2026-05-09 12:34:05','2026-05-09 12:34:05'),(54,11,4,'Rencontrer de nouvelles personnes','Je suis votre voisin(e). Vous venez d\'arriver dans la ville et vous ne connaissez personne. Vous me demandez conseil pour rencontrer de nouvelles personnes.',NULL,'Rôle: Voisin','bx bx-group','2026-05-09 12:34:05','2026-05-09 12:34:05'),(55,11,5,'Rythme de travail au Canada','Vous vous intéressez au rythme du travail au Canada. Interrogez-moi sur les horaires de travail et les jours de congé au Canada. Comparez avec la situation dans votre pays.',NULL,'Rôle: Personne à interroger','bx bx-time','2026-05-09 12:34:05','2026-05-09 12:34:05'),(56,12,1,'Achat d\'appartement','Je suis agent immobilier. Vous cherchez à acheter un appartement. Vous avez vu une annonce qui vous intéresse. Vous me posez des questions sur l\'appartement (superficie, prix, quartier, etc.).',NULL,'Rôle: Agent immobilier','bx bx-home','2026-05-09 12:34:05','2026-05-09 12:34:05'),(57,12,2,'Activités après l\'école','Je suis parent d\'élève. Vous voulez inscrire vos enfants à une activité après l\'école. Vous me demandez des informations et des conseils sur les activités proposées dans le quartier (type d\'activités, horaires, tarifs, animateurs, etc.).',NULL,'Rôle: Parent d\'élève','bx bx-football','2026-05-09 12:34:05','2026-05-09 12:34:05'),(58,12,3,'Bénévolat','Je suis votre ami(e). Je suis bénévole dans une association qui distribue des repas aux sans-abris. Vous voulez devenir bénévole. Vous me posez des questions sur l\'association (organisation, conditions, emploi du temps, etc.).',NULL,'Rôle: Ami bénévole','bx bx-heart','2026-05-09 12:34:05','2026-05-09 12:34:05'),(59,12,4,'Nouveau travail','Je suis votre ancien(ne) collègue. Je viens de commencer un nouveau travail. Vous souhaitez changer d\'emploi. Vous me posez des questions pour avoir des informations sur mon travail et mon entreprise (activités, salaire, collègues, etc.).',NULL,'Rôle: Ancien collègue','bx bx-briefcase','2026-05-09 12:34:05','2026-05-09 12:34:05'),(60,12,5,'Garde d\'enfant','Nous sommes voisin(e)s. Je vous demande de garder mon enfant le week-end prochain. Vous acceptez. Vous me demandez ce que vous devez faire (horaires, activités, repas, etc.).',NULL,'Rôle: Voisin','bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(61,13,1,'Vacances au Canada','Je suis agent(e) de voyage. Vous souhaitez partir en vacances au Canada. Vous me demandez des renseignements (tarifs, lieux, type de séjour, etc.).',NULL,'Rôle: Agent de voyage','bx bx-plane','2026-05-09 12:34:05','2026-05-09 12:34:05'),(62,13,2,'Déplacements à vélo','Je suis un(e) ami(e) et je vis à Ottawa. Vous venez d\'arriver dans la ville et vous souhaitez vous déplacer à vélo. Vous me posez des questions sur ce moyen de transport (pistes cyclables, agences de location, matériel, etc.).',NULL,'Rôle: Ami habitant à Ottawa','bx bx-cycling','2026-05-09 12:34:05','2026-05-09 12:34:05'),(63,13,3,'Recherche de baby-sitter','Je suis votre collègue de bureau. Je recherche une baby-sitter pour garder mes enfants. Je vous demande si vous connaissez quelqu\'un dans votre entourage. Vous me posez des questions sur mes exigences, le salaire, les horaires et les tâches à faire.',NULL,'Rôle: Collègue de bureau','bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(64,13,4,'Connaître le quartier','Je suis votre voisin(e). Vous venez d\'emménager, vous connaissez mal le quartier. Vous me posez des questions pour mieux le connaître (services, magasins, ambiance, etc.).',NULL,'Rôle: Voisin','bx bx-map','2026-05-09 12:34:05','2026-05-09 12:34:05'),(65,13,5,'Travaux dans le logement','Je travaille pour une entreprise, vous souhaitez faire des travaux dans votre logement. Vous me posez des questions (tarifs, durée, bruits, garantie, services, etc.).',NULL,'Rôle: Employé d\'entreprise de travaux','bx bx-wrench','2026-05-09 12:34:05','2026-05-09 12:34:05'),(66,14,1,'Auto-école','Je travaille dans une auto-école, vous voulez apprendre à conduire. Vous me posez des questions pour avoir des informations.',NULL,'Rôle: Employé d\'auto-école','bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(67,14,2,'Cours de langue','Je suis votre collègue, je fais des cours de langue payés par l\'entreprise, vous êtes intéressé. Posez moi des questions (langues, qualité, horaires, etc.).',NULL,'Rôle: Collègue','bx bx-book','2026-05-09 12:34:05','2026-05-09 12:34:05'),(68,14,3,'Location de voiture','Je travaille dans une agence de location de voiture, vous avez besoin d\'en louer une. Posez moi des questions (offre, prix, procédure, etc.).',NULL,'Rôle: Employé d\'agence de location','bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(69,14,4,'Cours de langue (duplicata)','Je suis votre collègue, je fais des cours de langue payés par l\'entreprise, vous êtes intéressé. Posez moi des questions (langues, qualité, horaires, etc.).',NULL,'Rôle: Collègue','bx bx-book','2026-05-09 12:34:05','2026-05-09 12:34:05'),(70,14,5,'Location de voiture (duplicata)','Je travaille dans une agence de location de voiture, vous avez besoin d\'en louer une. Posez moi des questions (offre, prix, procédure, etc.).',NULL,'Rôle: Employé d\'agence de location','bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(71,15,1,'Événement culturel','Je suis votre collègue, vous voulez m\'accompagner à événement culturel. Posez moi des questions (programme, date, lieu).',NULL,'Rôle: Collègue','bx bx-calendar-event','2026-05-09 12:34:05','2026-05-09 12:34:05'),(72,15,2,'Assurance automobile','Je travaille dans une compagnie d\'assurance automobile. Vous envisagez de souscrire à une assurance auto. Posez-moi des questions.',NULL,'Rôle: Employé d\'assurance','bx bx-car','2026-05-09 12:34:05','2026-05-09 12:34:05'),(73,15,3,'Séjour au Canada','Je travaille dans une agence de voyage. Vous êtes intéressé par un séjour au Canada. Posez-moi des questions.',NULL,'Rôle: Employé d\'agence de voyage','bx bx-trip','2026-05-09 12:34:05','2026-05-09 12:34:05'),(74,15,4,'Activités culturelles','Je travaille dans un centre culturel, posez-moi des questions pour participer à des activités (sport, théâtre, musées…).',NULL,'Rôle: Employé de centre culturel','bx bx-palette','2026-05-09 12:34:05','2026-05-09 12:34:05'),(75,15,5,'Garde d\'enfant','Je suis votre voisin, je vous demande de garder mon enfant de 3 ans ce week-end. Posez moi des questions.',NULL,'Rôle: Voisin','bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(76,16,1,'Baby-sitter','Je suis votre ami(e). J\'emploie un(e) baby-sitter toutes les semaines. Vous cherchez quelqu\'un pour garder votre enfant. Vous me posez des questions sur ma baby-sitter (disponibilité, tarifs, activités avec les enfants, …).',NULL,'Rôle: Ami','bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(77,16,2,'Vie au Canada','Je travaille dans une association franco-canadienne. Vous souhaitez vous installer au Canada. Vous me posez des questions pour savoir comment vivent les Canadiens (travail, loisirs, logement, etc.).',NULL,'Rôle: Employé d\'association','bx bx-building-house','2026-05-09 12:34:05','2026-05-09 12:34:05'),(78,16,3,'Garde d\'animal','Je suis votre ami(e). Je cherche une personne pour garder mon animal pendant mes vacances. Vous me posez des questions pour obtenir des informations (dates, activités, soins, …).',NULL,'Rôle: Ami','bx bx-dog','2026-05-09 12:34:05','2026-05-09 12:34:05'),(79,16,4,'Randonnées','Je suis votre voisin(e). Je travaille dans une agence qui organise des randonnées dans la forêt autour de Toronto. Vous êtes intéressé(e) et vous me posez des questions sur cette activité (circuits, tarifs, participants, etc.).',NULL,'Rôle: Voisin','bx bx-hiking','2026-05-09 12:34:05','2026-05-09 12:34:05'),(80,16,5,'Organisation d\'immeuble','Je suis votre voisin(e). Vous venez de vous installer dans l\'immeuble. Vous me posez des questions sur l\'organisation de l\'immeuble (habitants, règles de vie, équipements, etc.).',NULL,'Rôle: Voisin','bx bx-building','2026-05-09 12:34:05','2026-05-09 12:34:05'),(81,17,1,'Achat d\'appartement','Je suis agent immobilier. Vous cherchez à acheter un appartement. Vous avez vu une annonce qui vous intéresse. Vous me posez des questions sur l\'appartement (superficie, prix, quartier, etc.).',NULL,'Rôle: Agent immobilier','bx bx-home','2026-05-09 12:34:05','2026-05-09 12:34:05'),(82,17,2,'Activités après l\'école','Je suis parent d\'élève. Vous voulez inscrire vos enfants à une activité après l\'école. Vous me demandez des informations et des conseils sur les activités dans le quartier (types d\'activités, horaires, tarifs, animateurs, etc.).',NULL,'Rôle: Parent d\'élève','bx bx-football','2026-05-09 12:34:05','2026-05-09 12:34:05'),(83,17,3,'Bénévolat','Je suis votre ami(e). Je suis bénévole dans une association qui distribue des repas aux sans-abris. Vous voulez devenir bénévole. Vous me posez des questions sur l\'association (organisation, conditions, emploi du temps, etc.).',NULL,'Rôle: Ami bénévole','bx bx-heart','2026-05-09 12:34:05','2026-05-09 12:34:05'),(84,17,4,'Nouveau travail','Je suis votre ancien collègue. Je viens de commencer un nouveau travail. Vous souhaitez changer d\'emploi. Vous me posez des questions pour avoir des informations sur mon travail et mon entreprise (activités, salaire, collègues, etc.).',NULL,'Rôle: Ancien collègue','bx bx-briefcase','2026-05-09 12:34:05','2026-05-09 12:34:05'),(85,17,5,'Garde d\'enfant','Nous sommes voisin(e)s. Je vous demande de garder mon enfant le week-end prochain. Vous acceptez, vous me demandez ce que vous devez faire (horaires, activités, repas, etc.).',NULL,'Rôle: Voisin','bx bx-child','2026-05-09 12:34:05','2026-05-09 12:34:05'),(86,18,1,'Vie étudiante à Toronto','Je suis votre ami(e). J\'étudie depuis un an dans une université à Toronto. Vous allez bientôt partir étudier dans cette ville. Posez-moi des questions pour connaître la vie étudiante à Toronto (cours à l\'université, associations pour les étudiants, coûts de vie, …).',NULL,'Rôle: Ami étu